"use client";

import {
  useState,
  useRef,
  useEffect,
  useCallback,
  type CSSProperties,
} from "react";
import { createClient } from "@/lib/supabase/client";
import {
  estimateAvatarCredits,
  getCreditBreakdown,
} from "@/lib/avatar/pricing";
import type {
  AvatarAspectRatio,
  AvatarDuration,
  AvatarRenderOptions,
  AvatarResolution,
} from "@/lib/avatar/types";

type Phase = "upload" | "options" | "consent" | "render";

async function getVideoDurationSeconds(file: File): Promise<number> {
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file);
    const video = document.createElement("video");
    video.preload = "metadata";
    video.onloadedmetadata = () => {
      URL.revokeObjectURL(url);
      resolve(video.duration);
    };
    video.onerror = () => {
      URL.revokeObjectURL(url);
      reject(new Error("Video konnte nicht gelesen werden."));
    };
    video.src = url;
  });
}

function optionBtnStyle(active: boolean): CSSProperties {
  return {
    padding: "8px 16px",
    borderRadius: 6,
    border: active ? "1px solid #B4FF00" : "1px solid rgba(255,255,255,0.15)",
    background: active ? "#B4FF00" : "transparent",
    color: active ? "#060608" : "rgba(255,255,255,0.7)",
    fontSize: 13,
    fontWeight: active ? 700 : 500,
    cursor: "pointer",
    fontFamily: "inherit",
  };
}

function toggleBtnStyle(active: boolean): CSSProperties {
  return {
    padding: "4px 12px",
    borderRadius: 4,
    border: active ? "1px solid #B4FF00" : "1px solid rgba(255,255,255,0.15)",
    background: active ? "#B4FF00" : "transparent",
    color: active ? "#060608" : "rgba(255,255,255,0.5)",
    fontSize: 11,
    cursor: "pointer",
    fontFamily: "inherit",
  };
}

export default function AvatarStudioPage() {
  const [phase, setPhase] = useState<Phase>("upload");

  const [sourceImage, setSourceImage] = useState<string | null>(null);
  const [sourceImageFile, setSourceImageFile] = useState<File | null>(null);
  const [drivingVideo, setDrivingVideo] = useState<string | null>(null);
  const [drivingVideoFile, setDrivingVideoFile] = useState<File | null>(null);
  const [videoMode, setVideoMode] = useState<"upload" | "webcam">("upload");
  const [recording, setRecording] = useState(false);
  const [countdown, setCountdown] = useState<number | null>(null);

  const [options, setOptions] = useState<AvatarRenderOptions>({
    durationSeconds: 30,
    resolution: "720p",
    aspectRatio: "9:16",
    subtitles: false,
    branding: false,
    voiceover: false,
  });

  const [consentGiven, setConsentGiven] = useState(false);

  const [jobStatus, setJobStatus] = useState<string>("queued");
  const [resultUrl, setResultUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [rendering, setRendering] = useState(false);

  const imageRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const webcamRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const drivingVideoUrlRef = useRef<string | null>(null);

  const mediaBoxHeight = "h-[160px] sm:h-[200px]";

  const setDrivingVideoPreview = useCallback((url: string | null) => {
    if (drivingVideoUrlRef.current) {
      URL.revokeObjectURL(drivingVideoUrlRef.current);
      drivingVideoUrlRef.current = null;
    }
    if (url) drivingVideoUrlRef.current = url;
    setDrivingVideo(url);
  }, []);

  const stopWebcam = useCallback(() => {
    streamRef.current?.getTracks().forEach((t) => t.stop());
    streamRef.current = null;
    if (webcamRef.current) webcamRef.current.srcObject = null;
  }, []);

  const startWebcam = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: 640, height: 480, facingMode: "user" },
        audio: false,
      });
      streamRef.current = stream;
      if (webcamRef.current) {
        webcamRef.current.srcObject = stream;
        await webcamRef.current.play();
      }
    } catch {
      setError("Kamera-Zugriff verweigert. Bitte Kamera erlauben.");
    }
  }, []);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current?.state === "recording") {
      mediaRecorderRef.current.stop();
    }
  }, []);

  const startRecording = useCallback(async () => {
    if (!streamRef.current) return;

    setCountdown(3);
    await new Promise<void>((resolve) => {
      let c = 3;
      const interval = setInterval(() => {
        c--;
        setCountdown(c);
        if (c <= 0) {
          clearInterval(interval);
          setCountdown(null);
          resolve();
        }
      }, 1000);
    });

    chunksRef.current = [];
    const mimeType = MediaRecorder.isTypeSupported("video/webm;codecs=vp8")
      ? "video/webm;codecs=vp8"
      : "video/webm";
    const mr = new MediaRecorder(streamRef.current, { mimeType });
    mr.ondataavailable = (e) => {
      if (e.data.size > 0) chunksRef.current.push(e.data);
    };
    mr.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: mimeType });
      const file = new File([blob], "webcam.webm", { type: mimeType });
      setDrivingVideoFile(file);
      setDrivingVideoPreview(URL.createObjectURL(blob));
      setRecording(false);
    };
    mediaRecorderRef.current = mr;
    mr.start();
    setRecording(true);

    setTimeout(() => {
      if (mr.state === "recording") mr.stop();
    }, 10000);
  }, [setDrivingVideoPreview]);

  useEffect(() => {
    return () => {
      stopWebcam();
      if (mediaRecorderRef.current?.state === "recording") {
        mediaRecorderRef.current.stop();
      }
      if (drivingVideoUrlRef.current) {
        URL.revokeObjectURL(drivingVideoUrlRef.current);
      }
    };
  }, [stopWebcam]);

  async function uploadFile(
    file: File,
    path: string
  ): Promise<{ key: string; url: string }> {
    const supabase = createClient();
    const { error: uploadError } = await supabase.storage
      .from("avatar-assets")
      .upload(path, file, { contentType: file.type, upsert: true });
    if (uploadError) throw new Error(uploadError.message);
    const { data } = supabase.storage.from("avatar-assets").getPublicUrl(path);
    return { key: path, url: data.publicUrl };
  }

  const handleVideoFile = async (file: File) => {
    if (file.size > 50 * 1024 * 1024) {
      setError("Video zu gro├ƒ. Max. 50MB.");
      return;
    }
    try {
      const duration = await getVideoDurationSeconds(file);
      if (duration > 30) {
        setError("Video zu lang. Maximal 30 Sekunden.");
        return;
      }
    } catch {
      setError("Video konnte nicht gepr├╝ft werden.");
      return;
    }
    setDrivingVideoFile(file);
    setDrivingVideoPreview(URL.createObjectURL(file));
    setError(null);
  };

  const handleStartRender = async () => {
    if (!sourceImageFile || !drivingVideoFile || !consentGiven) return;

    setError(null);
    setRendering(true);
    setPhase("render");
    setJobStatus("uploading");
    setResultUrl(null);

    try {
      const supabase = createClient();
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) throw new Error("Nicht eingeloggt.");

      const ts = Date.now();
      const imageExt = sourceImageFile.name.split(".").pop() ?? "jpg";
      const videoExt = drivingVideoFile.name.split(".").pop() ?? "mp4";

      const [imageUpload, videoUpload] = await Promise.all([
        uploadFile(
          sourceImageFile,
          `${user.id}/avatar-studio/${ts}-source.${imageExt}`
        ),
        uploadFile(
          drivingVideoFile,
          `${user.id}/avatar-studio/${ts}-driving.${videoExt}`
        ),
      ]);

      setJobStatus("queued");

      const createRes = await fetch("/api/avatar/create-job", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          sourceImageKey: imageUpload.key,
          sourceImageUrl: imageUpload.url,
          drivingVideoKey: videoUpload.key,
          drivingVideoUrl: videoUpload.url,
          options,
          consentGiven: true,
        }),
      });
      const createData = await createRes.json();
      if (!createRes.ok) {
        throw new Error(createData.error ?? "Job konnte nicht erstellt werden.");
      }

      const newJobId = createData.job.id as string;
      setJobStatus("running");

      const startRes = await fetch("/api/avatar/start-render", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ jobId: newJobId }),
      });
      const startData = await startRes.json();
      if (!startRes.ok) {
        throw new Error(startData.error ?? "Render fehlgeschlagen.");
      }

      if (startData.videoUrl) {
        setResultUrl(startData.videoUrl as string);
      }
      setJobStatus("completed");
      window.dispatchEvent(new Event("credits-updated"));
    } catch (err) {
      setJobStatus("failed");
      setError(
        err instanceof Error ? err.message : "Unbekannter Fehler. Bitte erneut versuchen."
      );
    } finally {
      setRendering(false);
    }
  };

  const resetAll = () => {
    stopWebcam();
    setPhase("upload");
    setSourceImage(null);
    setSourceImageFile(null);
    setDrivingVideoFile(null);
    setDrivingVideoPreview(null);
    setVideoMode("upload");
    setConsentGiven(false);
    setJobId(null);
    setJobStatus("queued");
    setResultUrl(null);
    setError(null);
    setRendering(false);
  };

  const canContinueUpload = !!sourceImageFile && !!drivingVideoFile;

  const primaryBtn = (enabled: boolean): CSSProperties => ({
    padding: "14px 24px",
    borderRadius: 6,
    border: "none",
    background: enabled ? "#B4FF00" : "rgba(180,255,0,0.3)",
    color: "#060608",
    opacity: 1,
    fontSize: 14,
    fontWeight: 800,
    cursor: enabled ? "pointer" : "not-allowed",
    letterSpacing: "0.04em",
    textTransform: "uppercase",
    fontFamily: "inherit",
  });

  const ghostBtn: CSSProperties = {
    padding: "14px 24px",
    borderRadius: 6,
    border: "1px solid rgba(255,255,255,0.15)",
    background: "transparent",
    color: "rgba(255,255,255,0.7)",
    fontSize: 13,
    cursor: "pointer",
    fontFamily: "inherit",
  };

  return (
    <div
      style={{
        padding: "32px 24px",
        maxWidth: 900,
        margin: "0 auto",
        fontFamily: "DM Sans, sans-serif",
      }}
    >
      <style>{`
        @keyframes avatar-studio-rec-pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.35; }
        }
      `}</style>

      <div style={{ marginBottom: 32 }}>
        <div
          style={{
            fontSize: 10,
            color: "#B4FF00",
            letterSpacing: "0.14em",
            textTransform: "uppercase",
            marginBottom: 8,
          }}
        >
          Creator Studio
        </div>
        <h1
          style={{
            fontSize: 36,
            fontWeight: 900,
            color: "#fff",
            letterSpacing: "0.04em",
            textTransform: "uppercase",
            marginBottom: 8,
          }}
        >
          AVATAR STUDIO
        </h1>
        <p style={{ fontSize: 14, color: "rgba(255,255,255,0.5)", lineHeight: 1.6 }}>
          Hochwertiger Live-Avatar-Export ÔÇö Bild + Bewegungsvideo, Optionen w├ñhlen,
          rendern.
        </p>
      </div>

      {error && phase !== "render" && (
        <div
          style={{
            padding: "12px 16px",
            borderRadius: 6,
            border: "1px solid rgba(255,80,80,0.3)",
            background: "rgba(255,80,80,0.06)",
            color: "rgba(255,120,120,0.9)",
            fontSize: 13,
            marginBottom: 16,
          }}
        >
          {error}
        </div>
      )}

      {phase === "upload" && (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
            <div>
              <div
                style={{
                  fontSize: 10,
                  color: "rgba(180,255,0,0.6)",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  marginBottom: 8,
                }}
              >
                Avatar-Bild
              </div>
              <div
                onClick={() => imageRef.current?.click()}
                className={mediaBoxHeight}
                style={{
                  border: sourceImage
                    ? "1px solid rgba(180,255,0,0.4)"
                    : "1px dashed rgba(255,255,255,0.2)",
                  borderRadius: 8,
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  justifyContent: "center",
                  cursor: "pointer",
                  overflow: "hidden",
                  background: "rgba(255,255,255,0.02)",
                }}
              >
                {sourceImage ? (
                  <img
                    src={sourceImage}
                    alt="Avatar"
                    style={{ width: "100%", height: "100%", objectFit: "cover" }}
                  />
                ) : (
                  <>
                    <div style={{ fontSize: 32, marginBottom: 8, opacity: 0.4 }}>
                      Ôù╗
                    </div>
                    <div
                      style={{
                        fontSize: 13,
                        color: "rgba(255,255,255,0.5)",
                        textAlign: "center",
                        padding: "0 16px",
                      }}
                    >
                      JPG, PNG, WebP ┬À Gesicht frontal
                    </div>
                  </>
                )}
              </div>
              <input
                ref={imageRef}
                type="file"
                accept="image/jpeg,image/png,image/webp"
                style={{ display: "none" }}
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;
                  setSourceImageFile(file);
                  const reader = new FileReader();
                  reader.onload = (ev) =>
                    setSourceImage(ev.target?.result as string);
                  reader.readAsDataURL(file);
                }}
              />
            </div>

            <div>
              <div
                style={{
                  fontSize: 10,
                  color: "rgba(180,255,0,0.6)",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  marginBottom: 8,
                }}
              >
                Driving Video
              </div>
              <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
                <button
                  type="button"
                  onClick={() => {
                    setVideoMode("upload");
                    stopWebcam();
                  }}
                  style={toggleBtnStyle(videoMode === "upload")}
                >
                  Video hochladen
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setVideoMode("webcam");
                    void startWebcam();
                  }}
                  style={toggleBtnStyle(videoMode === "webcam")}
                >
                  Webcam aufnehmen
                </button>
              </div>

              {videoMode === "upload" ? (
                <>
                  <div
                    onClick={() => videoRef.current?.click()}
                    className={mediaBoxHeight}
                    style={{
                      border: drivingVideo
                        ? "1px solid rgba(180,255,0,0.4)"
                        : "1px dashed rgba(255,255,255,0.2)",
                      borderRadius: 8,
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      justifyContent: "center",
                      cursor: "pointer",
                      overflow: "hidden",
                      background: "rgba(255,255,255,0.02)",
                    }}
                  >
                    {drivingVideo ? (
                      <video
                        src={drivingVideo}
                        controls
                        style={{
                          width: "100%",
                          height: "100%",
                          objectFit: "cover",
                        }}
                      />
                    ) : (
                      <>
                        <div
                          style={{ fontSize: 32, marginBottom: 8, opacity: 0.4 }}
                        >
                          ÔûÂ
                        </div>
                        <div
                          style={{
                            fontSize: 13,
                            color: "rgba(255,255,255,0.5)",
                            textAlign: "center",
                            padding: "0 16px",
                          }}
                        >
                          MP4 ┬À Max. 50MB ┬À Max. 30 Sek.
                        </div>
                      </>
                    )}
                  </div>
                  <input
                    ref={videoRef}
                    type="file"
                    accept="video/mp4,video/quicktime"
                    style={{ display: "none" }}
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) void handleVideoFile(file);
                    }}
                  />
                </>
              ) : drivingVideo ? (
                <div
                  className={mediaBoxHeight}
                  style={{
                    border: "1px solid rgba(180,255,0,0.3)",
                    borderRadius: 8,
                    overflow: "hidden",
                    position: "relative",
                    background: "#000",
                  }}
                >
                  <video
                    src={drivingVideo}
                    controls
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                    }}
                  />
                  <div
                    style={{
                      position: "absolute",
                      bottom: 12,
                      left: "50%",
                      transform: "translateX(-50%)",
                    }}
                  >
                    <button
                      type="button"
                      onClick={() => {
                        setDrivingVideoFile(null);
                        setDrivingVideoPreview(null);
                      }}
                      style={{
                        padding: "6px 14px",
                        borderRadius: 20,
                        border: "1px solid rgba(255,255,255,0.3)",
                        background: "rgba(0,0,0,0.7)",
                        color: "rgba(255,255,255,0.7)",
                        fontSize: 11,
                        cursor: "pointer",
                        fontFamily: "inherit",
                      }}
                    >
                      Ôå║ Neu aufnehmen
                    </button>
                  </div>
                </div>
              ) : (
                <div
                  className={mediaBoxHeight}
                  style={{
                    border: "1px solid rgba(180,255,0,0.3)",
                    borderRadius: 8,
                    overflow: "hidden",
                    position: "relative",
                    background: "#000",
                  }}
                >
                  <video
                    ref={webcamRef}
                    muted
                    playsInline
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                      transform: "scaleX(-1)",
                    }}
                  />
                  {countdown !== null && (
                    <div
                      style={{
                        position: "absolute",
                        inset: 0,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        background: "rgba(0,0,0,0.5)",
                        fontSize: 72,
                        fontWeight: 900,
                        color: "#B4FF00",
                      }}
                    >
                      {countdown}
                    </div>
                  )}
                  {recording && (
                    <div
                      style={{
                        position: "absolute",
                        top: 12,
                        left: 12,
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        background: "rgba(0,0,0,0.7)",
                        padding: "4px 10px",
                        borderRadius: 20,
                      }}
                    >
                      <div
                        style={{
                          width: 8,
                          height: 8,
                          borderRadius: "50%",
                          background: "#ff4444",
                          animation: "avatar-studio-rec-pulse 1s infinite",
                        }}
                      />
                      <span style={{ fontSize: 11, color: "#fff" }}>REC</span>
                    </div>
                  )}
                  <div
                    style={{
                      position: "absolute",
                      bottom: 12,
                      left: "50%",
                      transform: "translateX(-50%)",
                    }}
                  >
                    {!recording ? (
                      <button
                        type="button"
                        onClick={() => void startRecording()}
                        style={{
                          padding: "8px 20px",
                          borderRadius: 20,
                          border: "2px solid #B4FF00",
                          background: "rgba(180,255,0,0.15)",
                          color: "#B4FF00",
                          fontSize: 12,
                          fontWeight: 700,
                          cursor: "pointer",
                          fontFamily: "inherit",
                        }}
                      >
                        ÔùÅ Aufnahme starten (max. 10 Sek.)
                      </button>
                    ) : (
                      <button
                        type="button"
                        onClick={stopRecording}
                        style={{
                          padding: "8px 20px",
                          borderRadius: 20,
                          border: "2px solid #ff4444",
                          background: "rgba(255,68,68,0.15)",
                          color: "#ff4444",
                          fontSize: 12,
                          fontWeight: 700,
                          cursor: "pointer",
                          fontFamily: "inherit",
                        }}
                      >
                        Ôûá Aufnahme stoppen
                      </button>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>

          <button
            type="button"
            disabled={!canContinueUpload}
            className="disabled:opacity-100 w-full sm:w-auto"
            style={primaryBtn(canContinueUpload)}
            onClick={() => setPhase("options")}
          >
            Weiter
          </button>
        </>
      )}

      {phase === "options" && (
        <div className="grid grid-cols-1 md:grid-cols-[1fr_280px] gap-8">
          <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>
            <div>
              <div
                style={{
                  fontSize: 10,
                  color: "rgba(180,255,0,0.6)",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  marginBottom: 10,
                }}
              >
                Dauer
              </div>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                {([15, 30, 60] as AvatarDuration[]).map((d) => (
                  <button
                    key={d}
                    type="button"
                    style={optionBtnStyle(options.durationSeconds === d)}
                    onClick={() =>
                      setOptions((o) => ({ ...o, durationSeconds: d }))
                    }
                  >
                    {d}s
                  </button>
                ))}
              </div>
            </div>

            <div>
              <div
                style={{
                  fontSize: 10,
                  color: "rgba(180,255,0,0.6)",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  marginBottom: 10,
                }}
              >
                Aufl├Âsung
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                {(["720p", "1080p"] as AvatarResolution[]).map((r) => (
                  <button
                    key={r}
                    type="button"
                    style={optionBtnStyle(options.resolution === r)}
                    onClick={() => setOptions((o) => ({ ...o, resolution: r }))}
                  >
                    {r}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <div
                style={{
                  fontSize: 10,
                  color: "rgba(180,255,0,0.6)",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  marginBottom: 10,
                }}
              >
                Format
              </div>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                {(["9:16", "1:1", "16:9"] as AvatarAspectRatio[]).map((a) => (
                  <button
                    key={a}
                    type="button"
                    style={optionBtnStyle(options.aspectRatio === a)}
                    onClick={() => setOptions((o) => ({ ...o, aspectRatio: a }))}
                  >
                    {a}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <div
                style={{
                  fontSize: 10,
                  color: "rgba(180,255,0,0.6)",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  marginBottom: 10,
                }}
              >
                Extras
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                {(
                  [
                    {
                      key: "subtitles" as const,
                      label: "Untertitel (+1 Credit)",
                    },
                    {
                      key: "branding" as const,
                      label: "Branding Overlay (+1 Credit)",
                    },
                    {
                      key: "voiceover" as const,
                      label: "KI-Voiceover (+2 Credits)",
                    },
                  ] as const
                ).map(({ key, label }) => (
                  <label
                    key={key}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 12,
                      cursor: "pointer",
                      fontSize: 13,
                      color: "rgba(255,255,255,0.85)",
                    }}
                  >
                    <input
                      type="checkbox"
                      checked={options[key]}
                      onChange={(e) =>
                        setOptions((o) => ({ ...o, [key]: e.target.checked }))
                      }
                      style={{ accentColor: "#B4FF00", width: 16, height: 16 }}
                    />
                    {label}
                  </label>
                ))}
              </div>
            </div>
          </div>

          <div
            style={{
              border: "1px solid rgba(180,255,0,0.2)",
              borderRadius: 8,
              padding: 20,
              background: "rgba(180,255,0,0.04)",
              height: "fit-content",
            }}
          >
            <div
              style={{
                fontSize: 11,
                fontWeight: 700,
                color: "#B4FF00",
                letterSpacing: "0.1em",
                textTransform: "uppercase",
                marginBottom: 16,
              }}
            >
              Credit Breakdown
            </div>
            {getCreditBreakdown(options).map((item) => (
              <div
                key={item.label}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  fontSize: 13,
                  color: "rgba(255,255,255,0.7)",
                  padding: "4px 0",
                }}
              >
                <span>{item.label}</span>
                <span style={{ color: "#B4FF00" }}>{item.credits} Credits</span>
              </div>
            ))}
            <div
              style={{
                borderTop: "1px solid rgba(255,255,255,0.1)",
                paddingTop: 8,
                marginTop: 8,
                display: "flex",
                justifyContent: "space-between",
                fontWeight: 700,
              }}
            >
              <span style={{ color: "#fff" }}>Gesamt</span>
              <span style={{ color: "#B4FF00" }}>
                {estimateAvatarCredits(options)} Credits
              </span>
            </div>
            <p
              style={{
                marginTop: 12,
                fontSize: 11,
                color: "rgba(255,255,255,0.45)",
                lineHeight: 1.5,
              }}
            >
              Credits werden erst nach erfolgreichem Render abgebucht.
            </p>
          </div>

          <div
            className="md:col-span-2"
            style={{ display: "flex", gap: 12, flexWrap: "wrap" }}
          >
            <button type="button" style={ghostBtn} onClick={() => setPhase("upload")}>
              Zur├╝ck
            </button>
            <button
              type="button"
              style={primaryBtn(true)}
              onClick={() => setPhase("consent")}
            >
              Weiter
            </button>
          </div>
        </div>
      )}

      {phase === "consent" && (
        <>
          <div
            style={{
              border: "1px solid rgba(180,255,0,0.25)",
              borderRadius: 8,
              padding: 24,
              background: "rgba(180,255,0,0.04)",
              marginBottom: 24,
            }}
          >
            <div
              style={{
                fontSize: 16,
                fontWeight: 700,
                color: "#fff",
                marginBottom: 12,
              }}
            >
              Einwilligung erforderlich
            </div>
            <p
              style={{
                fontSize: 13,
                color: "rgba(255,255,255,0.7)",
                lineHeight: 1.7,
                marginBottom: 20,
              }}
            >
              Ich best├ñtige, dass ich die Rechte an dem verwendeten Bild und Video
              besitze und die gezeigte Person mit der KI-Nutzung einverstanden ist.
              Ich verwende ausschlie├ƒlich eigenes oder lizenziertes Material. Die
              Nutzung fremder Personen ohne Zustimmung ist nicht erlaubt.
            </p>
            <label
              style={{
                display: "flex",
                alignItems: "flex-start",
                gap: 12,
                cursor: "pointer",
              }}
            >
              <input
                type="checkbox"
                checked={consentGiven}
                onChange={(e) => setConsentGiven(e.target.checked)}
                style={{
                  marginTop: 2,
                  accentColor: "#B4FF00",
                  width: 16,
                  height: 16,
                  flexShrink: 0,
                }}
              />
              <span
                style={{
                  fontSize: 13,
                  color: "rgba(255,255,255,0.85)",
                  lineHeight: 1.5,
                }}
              >
                Ich stimme zu und best├ñtige die Einwilligung.
              </span>
            </label>
          </div>

          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            <button type="button" style={ghostBtn} onClick={() => setPhase("options")}>
              Zur├╝ck
            </button>
            <button
              type="button"
              disabled={!consentGiven || rendering}
              className="disabled:opacity-100 flex-1 sm:flex-none"
              style={primaryBtn(consentGiven && !rendering)}
              onClick={() => void handleStartRender()}
            >
              Avatar rendern ÔÇö {estimateAvatarCredits(options)} Credits
            </button>
          </div>
        </>
      )}

      {phase === "render" && (
        <div style={{ maxWidth: 520, margin: "0 auto" }}>
          {jobStatus === "failed" ? (
            <div
              style={{
                border: "1px solid rgba(255,80,80,0.3)",
                borderRadius: 8,
                padding: 24,
                background: "rgba(255,80,80,0.06)",
                marginBottom: 24,
              }}
            >
              <div
                style={{
                  fontSize: 16,
                  fontWeight: 700,
                  color: "#ff8a9a",
                  marginBottom: 8,
                }}
              >
                Ô£ù Render fehlgeschlagen ÔÇö keine Credits abgebucht.
              </div>
              <p style={{ fontSize: 13, color: "rgba(255,255,255,0.7)", marginBottom: 16 }}>
                {error ?? "Ein unbekannter Fehler ist aufgetreten."}
              </p>
              <button type="button" style={primaryBtn(true)} onClick={resetAll}>
                Erneut versuchen
              </button>
            </div>
          ) : jobStatus === "completed" ? (
            <div
              style={{
                border: "1px solid rgba(180,255,0,0.25)",
                borderRadius: 8,
                overflow: "hidden",
                marginBottom: 24,
              }}
            >
              <div
                style={{
                  padding: "10px 16px",
                  borderBottom: "1px solid rgba(255,255,255,0.07)",
                  fontSize: 11,
                  fontWeight: 700,
                  color: "#B4FF00",
                  letterSpacing: "0.08em",
                  textTransform: "uppercase",
                }}
              >
                Ô£ô Avatar fertig ÔÇö {estimateAvatarCredits(options)} Credits abgebucht.
              </div>
              {resultUrl ? (
                <video
                  src={resultUrl}
                  controls
                  style={{ width: "100%", display: "block", background: "#000" }}
                />
              ) : null}
              <div
                style={{
                  padding: 16,
                  display: "flex",
                  gap: 12,
                  flexWrap: "wrap",
                }}
              >
                {resultUrl && (
                  <a
                    href={resultUrl}
                    download="avatar-studio.mp4"
                    style={{
                      padding: "8px 16px",
                      borderRadius: 4,
                      background: "#B4FF00",
                      color: "#060608",
                      fontSize: 12,
                      fontWeight: 700,
                      textDecoration: "none",
                    }}
                  >
                    Herunterladen
                  </a>
                )}
                <button type="button" style={ghostBtn} onClick={resetAll}>
                  Nochmal rendern
                </button>
              </div>
            </div>
          ) : (
            <div
              style={{
                border: "1px solid rgba(180,255,0,0.2)",
                borderRadius: 8,
                padding: 32,
                textAlign: "center",
                background: "rgba(180,255,0,0.04)",
              }}
            >
              <p
                style={{
                  fontSize: 15,
                  fontWeight: 600,
                  color: "#fff",
                  marginBottom: 12,
                }}
              >
                ÔÅ│ Avatar wird generiert...
              </p>
              <p style={{ fontSize: 13, color: "rgba(255,255,255,0.55)", lineHeight: 1.6 }}>
                Bitte warten (30ÔÇô90 Sek.). Seite nicht schlie├ƒen.
              </p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { Suspense, useCallback, useEffect, useRef, useState } from "react";
import { useTranslations } from "next-intl";
import type {
  CompetitorAnalysisResponse,
  CompetitorAnalysisResult,
} from "@/lib/competitor-analysis";
import { COMPETITOR_ANALYSIS_CREDIT_COST } from "@/lib/competitor-analysis";
import { TablerSpy } from "@/components/icons/TablerSpy";
import { onGenerationActionResult, shouldShowInlineGenerationError } from "@/lib/handle-generation-result";
import { useOptimisticGeneration } from "@/hooks/use-optimistic-generation";
import { useUserCredits } from "@/hooks/use-user-credits";
import { createClient } from "@/lib/supabase/client";
import { sanitizeUserMessage } from "@/lib/sanitize-user-message";
import { AiOutputDisclaimer } from "@/components/ui/AiOutputDisclaimer";

const CREDIT_COST = COMPETITOR_ANALYSIS_CREDIT_COST;

type Step = "input" | "loading" | "results";

type HistoryRow = {
  id: string;
  prompt: string;
  created_at: string;
  result: CompetitorAnalysisResponse | null;
};

function formatNum(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n.toLocaleString("de-DE");
}

function TagList({
  items,
  color,
  borderColor,
  bg,
}: {
  items: string[];
  color: string;
  borderColor: string;
  bg: string;
}) {
  if (!items.length) return null;
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
      {items.map((item) => (
        <span
          key={item}
          style={{
            padding: "6px 12px",
            borderRadius: 99,
            fontSize: "0.82rem",
            color,
            background: bg,
            border: `1px solid ${borderColor}`,
          }}
        >
          {item}
        </span>
      ))}
    </div>
  );
}

function CompetitorPageInner() {
  const t = useTranslations("flows.competitor");
  const [step, setStep] = useState<Step>("input");
  const [channelUrl, setChannelUrl] = useState("");
  const [data, setData] = useState<CompetitorAnalysisResponse | null>(null);
  const [history, setHistory] = useState<HistoryRow[]>([]);
  const [error, setError] = useState<string | null>(null);
  const started = useRef(false);
  const { credits } = useUserCredits();
  const { generate } = useOptimisticGeneration();

  const loadHistory = useCallback(async () => {
    const supabase = createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) return;

    const { data: rows } = await supabase
      .from("generations")
      .select("id, prompt, created_at, result")
      .eq("user_id", user.id)
      .eq("type", "competitor_analysis")
      .order("created_at", { ascending: false })
      .limit(8);

    setHistory(
      (rows ?? []).map((row) => ({
        id: row.id,
        prompt: row.prompt,
        created_at: row.created_at,
        result: (row.result as CompetitorAnalysisResponse | null) ?? null,
      }))
    );
  }, []);

  useEffect(() => {
    void loadHistory();
  }, [loadHistory]);

  const inputStyle = {
    width: "100%",
    padding: "12px 16px",
    borderRadius: 10,
    background: "#18181d",
    border: "1px solid rgba(255,255,255,0.09)",
    color: "#F0EFE8",
    fontSize: "0.95rem",
    outline: "none" as const,
    fontFamily: "var(--font-dm), sans-serif",
  };

  const runAnalyze = async () => {
    if (started.current || credits === null || !channelUrl.trim()) return;
    started.current = true;
    setError(null);
    setStep("loading");

    try {
      const res = await generate(
        async () => {
          const r = await fetch("/api/competitor", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ channelUrl }),
          });
          const json = await r.json();
          if (!r.ok || !json.success) {
            return {
              success: false as const,
              error: json.error ?? t("error_generic"),
              credits: json.credits,
              required: json.required,
            };
          }
          return {
            success: true as const,
            creditsLeft: json.creditsLeft as number,
            channel: json.channel as CompetitorAnalysisResponse["channel"],
            topVideos: json.topVideos as CompetitorAnalysisResponse["topVideos"],
            analysis: json.analysis as CompetitorAnalysisResult,
          };
        },
        CREDIT_COST,
        credits
      );

      if (!res.success) {
        onGenerationActionResult(res);
        if (shouldShowInlineGenerationError(res)) {
          setError(sanitizeUserMessage(res.error));
        }
        setStep("input");
        return;
      }

      onGenerationActionResult({
        success: true,
        creditsLeft: res.creditsLeft,
      });

      setData({
        channel: res.channel,
        topVideos: res.topVideos,
        analysis: res.analysis,
      });
      setStep("results");
      void loadHistory();
    } catch {
      setError(t("error_generic"));
      setStep("input");
    } finally {
      started.current = false;
    }
  };

  const showResults = (payload: CompetitorAnalysisResponse) => {
    setData(payload);
    setStep("results");
  };

  const analysis: CompetitorAnalysisResult | null = data?.analysis ?? null;

  return (
    <div style={{ maxWidth: 920, margin: "0 auto", padding: "24px 20px 100px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 8 }}>
        <TablerSpy size={28} color="#B4FF00" strokeWidth={2.2} />
        <h1
          style={{
            margin: 0,
            fontSize: "1.65rem",
            fontWeight: 800,
            color: "#F0EFE8",
            fontFamily: "var(--font-syne), sans-serif",
          }}
        >
          {t("title")}
        </h1>
      </div>
      <p style={{ color: "rgba(255,255,255,0.65)", margin: "0 0 28px", fontSize: "0.95rem" }}>
        {t("description")}
      </p>

      {step === "input" && (
        <div
          style={{
            background: "#0f0f12",
            border: "1px solid rgba(255,255,255,0.07)",
            borderRadius: 16,
            padding: 24,
          }}
        >
          <label
            style={{
              fontSize: "0.78rem",
              fontWeight: 700,
              color: "rgba(255,255,255,0.65)",
              display: "block",
              marginBottom: 6,
              letterSpacing: "0.04em",
              textTransform: "uppercase",
            }}
          >
            {t("url_label")}
          </label>
          <input
            value={channelUrl}
            onChange={(e) => setChannelUrl(e.target.value)}
            placeholder={t("url_placeholder")}
            style={{ ...inputStyle, marginBottom: 16 }}
          />
          {error && (
            <p style={{ color: "#ff6b7a", marginBottom: 12, fontSize: "0.9rem" }}>
              {error}
            </p>
          )}
          <button
            type="button"
            onClick={() => void runAnalyze()}
            disabled={credits !== null && credits < CREDIT_COST}
            style={{
              width: "100%",
              padding: "14px 20px",
              borderRadius: 10,
              border: "none",
              background: "#B4FF00",
              color: "#060608",
              fontWeight: 800,
              fontSize: "1rem",
              cursor: "pointer",
            }}
          >
            {t("button", { cost: CREDIT_COST })}
          </button>
        </div>
      )}

      {step === "loading" && (
        <div
          style={{
            textAlign: "center",
            padding: 48,
            background: "#0f0f12",
            borderRadius: 16,
            border: "1px solid rgba(180,255,0,0.15)",
          }}
        >
          <div
            style={{
              width: 48,
              height: 48,
              margin: "0 auto 16px",
              border: "3px solid rgba(180,255,0,0.2)",
              borderTopColor: "#B4FF00",
              borderRadius: "50%",
              animation: "spin 0.9s linear infinite",
            }}
          />
          <p style={{ color: "#B4FF00", fontWeight: 700 }}>{t("analyzing")}</p>
        </div>
      )}

      {step === "results" && data && analysis && (
        <div>
          <div
            style={{
              display: "flex",
              gap: 20,
              alignItems: "center",
              padding: 24,
              borderRadius: 16,
              background: "#0f0f12",
              border: "1px solid rgba(180,255,0,0.2)",
              marginBottom: 20,
            }}
          >
            {data.channel.thumbnailUrl && (
              <img
                src={data.channel.thumbnailUrl}
                alt=""
                width={72}
                height={72}
                style={{ borderRadius: "50%", objectFit: "cover" }}
              />
            )}
            <div>
              <h2 style={{ margin: "0 0 6px", color: "#F0EFE8", fontSize: "1.35rem" }}>
                {data.channel.title}
              </h2>
              <p style={{ margin: 0, color: "#B4FF00", fontWeight: 700 }}>
                {formatNum(data.channel.subscriberCount)} {t("subscribers")}
              </p>
            </div>
          </div>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))",
              gap: 12,
              marginBottom: 20,
            }}
          >
            {[
              { label: t("stat_avg_views"), value: formatNum(analysis.avg_views) },
              {
                label: t("stat_posting"),
                value: analysis.posting_frequency,
              },
              {
                label: t("stat_videos"),
                value: formatNum(data.channel.videoCount),
              },
            ].map((s) => (
              <div
                key={s.label}
                style={{
                  padding: 16,
                  borderRadius: 12,
                  background: "#18181d",
                  border: "1px solid rgba(255,255,255,0.07)",
                }}
              >
                <p style={{ margin: "0 0 6px", fontSize: "0.72rem", color: "rgba(255,255,255,0.65)" }}>
                  {s.label}
                </p>
                <p
                  style={{
                    margin: 0,
                    fontSize: "1.05rem",
                    fontWeight: 800,
                    color: "#B4FF00",
                  }}
                >
                  {s.value}
                </p>
              </div>
            ))}
          </div>

          <p
            style={{
              color: "rgba(240,239,232,0.8)",
              lineHeight: 1.6,
              marginBottom: 24,
              fontSize: "0.95rem",
            }}
          >
            {analysis.summary}
          </p>

          <section style={{ marginBottom: 20 }}>
            <h3 style={{ color: "#F0EFE8", fontSize: "0.9rem", marginBottom: 10 }}>
              {t("top_topics")}
            </h3>
            <TagList
              items={analysis.top_topics}
              color="#060608"
              borderColor="rgba(180,255,0,0.45)"
              bg="#B4FF00"
            />
          </section>

          <section style={{ marginBottom: 20 }}>
            <h3 style={{ color: "#10b981", fontSize: "0.9rem", marginBottom: 10 }}>
              {t("content_gaps")}
            </h3>
            <TagList
              items={analysis.content_gaps}
              color="#10b981"
              borderColor="rgba(16,185,129,0.35)"
              bg="rgba(16,185,129,0.08)"
            />
          </section>

          <section style={{ marginBottom: 20 }}>
            <h3 style={{ color: "#f59e0b", fontSize: "0.9rem", marginBottom: 10 }}>
              {t("weaknesses")}
            </h3>
            <TagList
              items={analysis.weaknesses}
              color="#f59e0b"
              borderColor="rgba(245,158,11,0.35)"
              bg="rgba(245,158,11,0.08)"
            />
          </section>

          <section style={{ marginBottom: 24 }}>
            <h3 style={{ color: "#B4FF00", fontSize: "0.9rem", marginBottom: 10 }}>
              {t("opportunities")}
            </h3>
            <div
              style={{
                padding: 22,
                borderRadius: 14,
                background: "rgba(180,255,0,0.1)",
                border: "2px solid rgba(180,255,0,0.45)",
              }}
            >
              {analysis.opportunities.length > 0 ? (
                <ul
                  style={{
                    margin: 0,
                    paddingLeft: 20,
                    color: "#F0EFE8",
                    lineHeight: 1.65,
                    fontSize: "0.95rem",
                  }}
                >
                  {analysis.opportunities.map((item) => (
                    <li key={item} style={{ marginBottom: 10 }}>
                      <span style={{ color: "#B4FF00", fontWeight: 700 }}>ÔåÆ </span>
                      {item}
                    </li>
                  ))}
                </ul>
              ) : (
                <p style={{ margin: 0, color: "rgba(255,255,255,0.65)" }}>ÔÇö</p>
              )}
            </div>
          </section>

          {analysis.best_performing_format && (
            <p
              style={{
                marginBottom: 24,
                fontSize: "0.88rem",
                color: "rgba(255,255,255,0.65)",
              }}
            >
              <strong style={{ color: "#F0EFE8" }}>{t("best_format")}:</strong>{" "}
              {analysis.best_performing_format}
            </p>
          )}

          <h3 style={{ color: "#F0EFE8", marginBottom: 12 }}>{t("top_videos")}</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {data.topVideos.map((v, i) => (
              <a
                key={v.videoId}
                href={`https://www.youtube.com/watch?v=${v.videoId}`}
                target="_blank"
                rel="noopener noreferrer"
                style={{
                  display: "flex",
                  gap: 14,
                  padding: 14,
                  borderRadius: 12,
                  background: "#0f0f12",
                  border: "1px solid rgba(255,255,255,0.07)",
                  textDecoration: "none",
                  color: "inherit",
                }}
              >
                {v.thumbnailUrl && (
                  <img
                    src={v.thumbnailUrl}
                    alt=""
                    width={96}
                    height={54}
                    style={{ borderRadius: 8, objectFit: "cover", flexShrink: 0 }}
                  />
                )}
                <div style={{ minWidth: 0 }}>
                  <span style={{ color: "#B4FF00", fontWeight: 800, fontSize: "0.75rem" }}>
                    #{i + 1}
                  </span>
                  <p
                    style={{
                      margin: "4px 0 0",
                      color: "#F0EFE8",
                      fontWeight: 600,
                      fontSize: "0.9rem",
                      lineHeight: 1.35,
                    }}
                  >
                    {v.title}
                  </p>
                  <p style={{ margin: "6px 0 0", color: "rgba(255,255,255,0.65)", fontSize: "0.8rem" }}>
                    {formatNum(v.viewCount)} Views
                  </p>
                </div>
              </a>
            ))}
          </div>

          <button
            type="button"
            onClick={() => {
              setStep("input");
              setData(null);
            }}
            style={{
              marginTop: 28,
              padding: "12px 20px",
              borderRadius: 10,
              border: "1px solid rgba(255,255,255,0.12)",
              background: "transparent",
              color: "#F0EFE8",
              cursor: "pointer",
              fontWeight: 600,
            }}
          >
            {t("analyze_again")}
          </button>
          <AiOutputDisclaimer />
        </div>
      )}

      {history.length > 0 && (
        <section style={{ marginTop: 40 }}>
          <h2
            style={{
              fontSize: "1rem",
              color: "rgba(255,255,255,0.65)",
              textTransform: "uppercase",
              letterSpacing: "0.08em",
              marginBottom: 14,
            }}
          >
            {t("history_title")}
          </h2>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {history.map((h) => (
              <button
                key={h.id}
                type="button"
                onClick={() => {
                  if (h.result) showResults(h.result);
                }}
                style={{
                  textAlign: "left",
                  padding: "12px 16px",
                  borderRadius: 10,
                  background: "#0f0f12",
                  border: "1px solid rgba(255,255,255,0.07)",
                  color: "#F0EFE8",
                  cursor: h.result ? "pointer" : "default",
                }}
              >
                <span style={{ color: "#B4FF00", fontWeight: 800, marginRight: 10 }}>
                  {h.result?.channel.title ?? "ÔÇö"}
                </span>
                {h.prompt}
              </button>
            ))}
          </div>
        </section>
      )}

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

export default function CompetitorPage() {
  return (
    <Suspense fallback={null}>
      <CompetitorPageInner />
    </Suspense>
  );
}

"use client";

import { Suspense, useCallback, useEffect, useRef, useState } from "react";
import Image from "next/image";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { BrainCircuit, UserRound } from "lucide-react";
import { KiInfluencerTrainingVisualizer } from "@/components/ki-influencer/KiInfluencerTrainingVisualizer";
import { ProtectedGeneratedImage } from "@/components/generated/ProtectedGeneratedImage";
import { AiOutputDisclaimer } from "@/components/ui/AiOutputDisclaimer";
import { LoadingButton } from "@/components/ui/LoadingButton";
import {
  DEFAULT_IMAGE_PLATFORM_ID,
  DEFAULT_IMAGE_STYLE_ID,
  IMAGE_STYLE_PRESETS,
  PLATFORM_FORMATS,
  type ImagePlatformId,
  type ImageStyleId,
} from "@/lib/ai/imageStylePresets";
import {
  apiBodyToErrorMessage,
  handleKiInfluencerApiError,
  isKiInfluencerApiFailure,
  KI_INFLUENCER_ERROR_MESSAGES,
  parseKiInfluencerJsonResponse,
  resolveWizardDisplayError,
  toErrorMessage,
  type KiInfluencerApiErrorBody,
} from "@/lib/ki-influencer-client-errors";
import type {
  CreateFromUploadResponse,
  FinalizeUploadResponse,
  TrainingSetImageResponse,
  TrainingSetStartResponse,
  UploadPhotoResponse,
} from "@/lib/ki-influencer-types";
import {
  isCreateFromUploadResponse,
  isTrainingSetImageResponse,
  isTrainingSetStartResponse,
} from "@/lib/ki-influencer-types";
import { IMAGE_GEN_CREDITS } from "@/lib/image-generator-credits";
import { calcLoraCredits } from "@/lib/lora-credits";
import {
  KI_INFLUENCER_LORA_STEPS,
  KI_INFLUENCER_TRAINING_SET_CREDITS,
  KI_INFLUENCER_TRAINING_SET_SIZE,
  KI_INFLUENCER_WIZARD_STEPS,
} from "@/lib/ki-influencer-config";
import { LORA_GENERATION_CREDIT, LORA_MAX_FILE_BYTES, LORA_MIN_IMAGES } from "@/lib/lora-config";
import { getSafeSearchParam } from "@/lib/safe-url-param";

type WizardStep = 0 | 1 | 2 | 3;
type PathMode = null | "generated" | "uploaded";
type WizardBusyAction =
  | "upload"
  | "casting"
  | "castingConfirm"
  | "loraTrain"
  | "content";

const UPLOAD_MAX_PHOTOS = 20;
const ALLOWED_UPLOAD_TYPES = new Set(["image/jpeg", "image/png", "image/webp"]);

const UPLOAD_TIPS = [
  "Nur EINE Person auf allen Fotos",
  "Verschiedene Blickwinkel und Gesichtsausdr├╝cke",
  "Gutes Licht, scharfes Gesicht",
  "Keine Sonnenbrillen oder verdeckte Gesichter",
] as const;

const DESCRIPTION_EXAMPLES = [
  "28-j├ñhrige Fitness-Influencerin, lange rotblonde Haare, gr├╝ne Augen, sportlich-nat├╝rlicher Look, Nische: Fitness & Ern├ñhrung",
  "32-j├ñhriger Tech-Creator, kurze dunkle Haare, Brille, moderner Casual-Style, Nische: Gadgets & KI",
  "25-j├ñhrige Beauty-Influencerin, lange braune Haare, eleganter Look, Nische: Mode & Make-up",
] as const;

const DESCRIPTION_EXAMPLE_LABELS = [
  "Fitness-Influencerin",
  "Tech-Creator",
  "Beauty & Fashion",
] as const;

const SCENE_EXAMPLES = [
  "Beim Fr├╝hst├╝ck mit Smoothie-Bowl",
  "Beim Workout im Fitnessstudio",
  "Golden Hour am Strand",
] as const;

const chipClass = (active: boolean) =>
  active
    ? "border-[#B4FF00] bg-[#B4FF00]/12 text-[#B4FF00]"
    : "border-white/12 text-[#F0EFE8]/65 hover:border-white/20";

function parseUrlWizardStep(raw: string | null): WizardStep {
  const stepFromUrl = Number(raw) || 1;
  return Math.min(3, Math.max(0, stepFromUrl - 1)) as WizardStep;
}

function KiInfluencerPageInner() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();

  const urlStep = searchParams.get("step");
  const urlId = searchParams.get("id");
  const urlName = getSafeSearchParam(searchParams, "name");
  const hasUrlWizardState = Boolean(urlStep || urlId);

  const [pathMode, setPathMode] = useState<PathMode>(
    hasUrlWizardState ? "generated" : null
  );
  const [step, setStep] = useState<WizardStep>(() => parseUrlWizardStep(urlStep));
  const [name, setName] = useState(urlName);
  const [description, setDescription] = useState("");
  const [characterId, setCharacterId] = useState<string | null>(urlId);
  const [castingImageUrl, setCastingImageUrl] = useState<string | null>(null);
  const [castingConfirmed, setCastingConfirmed] = useState(false);

  const [uploadFiles, setUploadFiles] = useState<File[]>([]);
  const [uploadPreviews, setUploadPreviews] = useState<string[]>([]);
  const [uploadConsent, setUploadConsent] = useState(false);
  const [uploadRightsConsent, setUploadRightsConsent] = useState(false);
  const [uploadDragOver, setUploadDragOver] = useState(false);
  const uploadFileRef = useRef<HTMLInputElement>(null);

  const [trainingProgress, setTrainingProgress] = useState(0);
  const [trainingSetRunning, setTrainingSetRunning] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  const [loraProgress, setLoraProgress] = useState(0);
  const [loraLogs, setLoraLogs] = useState<string[]>([]);
  const [consentAccepted, setConsentAccepted] = useState(false);
  const [characterReady, setCharacterReady] = useState(false);

  const [contentPrompt, setContentPrompt] = useState("");
  const [styleId, setStyleId] = useState<ImageStyleId>(DEFAULT_IMAGE_STYLE_ID);
  const [platform, setPlatform] = useState<ImagePlatformId>(
    DEFAULT_IMAGE_PLATFORM_ID
  );
  const [contentResultUrl, setContentResultUrl] = useState<string | null>(null);

  const [busyAction, setBusyAction] = useState<WizardBusyAction | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [schemaReady, setSchemaReady] = useState(false);
  const schemaReadyRef = useRef(false);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const loraTrainCredits = calcLoraCredits(KI_INFLUENCER_LORA_STEPS);

  const setWizardError = useCallback((message: string | null) => {
    if (!message) {
      setError(null);
      return;
    }
    setError(resolveWizardDisplayError(message, schemaReadyRef.current));
  }, []);

  useEffect(() => {
    const stepParam = searchParams.get("step");
    if (stepParam) setStep(parseUrlWizardStep(stepParam));
    const idParam = searchParams.get("id");
    if (idParam) setCharacterId(idParam);
    const nameParam = getSafeSearchParam(searchParams, "name");
    if (nameParam) setName(nameParam);
  }, [searchParams]);

  useEffect(() => {
    let cancelled = false;

    void (async () => {
      try {
        const res = await fetch("/api/ki-influencer/schema-status");
        const parsed = await parseKiInfluencerJsonResponse<
          KiInfluencerApiErrorBody & {
            ready?: boolean;
            missing?: string[];
          }
        >(res);
        if (cancelled) return;

        if (parsed.ok && parsed.data.ready) {
          schemaReadyRef.current = true;
          setSchemaReady(true);
          setError((prev) =>
            prev === KI_INFLUENCER_ERROR_MESSAGES.table_missing ? null : prev
          );
          return;
        }

        if (parsed.ok && (parsed.data.missing?.length ?? 0) > 0) {
          schemaReadyRef.current = false;
          setSchemaReady(false);
          setError(KI_INFLUENCER_ERROR_MESSAGES.table_missing);
        }
      } catch {
        /* ignore probe errors */
      }
    })();

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (!characterId) return;

    let cancelled = false;

    void (async () => {
      try {
        const res = await fetch(`/api/ki-influencer/character/${characterId}`);
        const parsed = await parseKiInfluencerJsonResponse<
          KiInfluencerApiErrorBody & {
            character?: {
              name?: string;
              source?: "generated" | "uploaded";
              status?: string;
              casting_image_url?: string | null;
            };
          }
        >(res);
        if (cancelled || !parsed.ok || !parsed.data.character) return;

        const character = parsed.data.character;
        if (character.name) setName(character.name);
        setPathMode(character.source === "uploaded" ? "uploaded" : "generated");
        if (character.casting_image_url) {
          setCastingImageUrl(character.casting_image_url);
        }
        if (
          character.status &&
          [
            "casting_confirmed",
            "training_set",
            "training_set_ready",
            "training",
            "ready",
          ].includes(character.status)
        ) {
          setCastingConfirmed(true);
        }
        if (character.status === "ready") {
          setCharacterReady(true);
        }
      } catch {
        /* ignore hydrate errors */
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [characterId]);

  const persistWizardUrl = useCallback(
    (overrides?: {
      step?: WizardStep;
      id?: string | null;
      name?: string;
    }) => {
      const nextStep = overrides?.step ?? step;
      const nextId = overrides?.id !== undefined ? overrides.id : characterId;
      const nextName = overrides?.name !== undefined ? overrides.name : name;

      const params = new URLSearchParams();
      if (nextStep > 0 || nextId || nextName.trim()) {
        params.set("step", String(nextStep + 1));
        if (nextId) params.set("id", nextId);
        if (nextName.trim()) params.set("name", nextName.trim());
      }

      const nextQs = params.toString();
      if (nextQs === searchParams.toString()) return;

      router.replace(nextQs ? `${pathname}?${nextQs}` : pathname, {
        scroll: false,
      });
    },
    [step, characterId, name, searchParams, router, pathname]
  );

  const goToStep = useCallback(
    (
      nextStep: WizardStep,
      extra?: { id?: string | null; name?: string }
    ) => {
      setStep(nextStep);
      persistWizardUrl({ step: nextStep, ...extra });
    },
    [persistWizardUrl]
  );

  const handleNameChange = useCallback(
    (value: string) => {
      setName(value);
      persistWizardUrl({ name: value });
    },
    [persistWizardUrl]
  );

  const addUploadFiles = (incoming: FileList | File[]) => {
    const next: File[] = [];
    for (const file of Array.from(incoming)) {
      if (!ALLOWED_UPLOAD_TYPES.has(file.type)) continue;
      if (file.size > LORA_MAX_FILE_BYTES) continue;
      next.push(file);
    }
    if (next.length === 0) return;
    setUploadFiles((prev) => {
      const merged = [...prev, ...next].slice(0, UPLOAD_MAX_PHOTOS);
      setUploadPreviews((old) => {
        old.forEach((url) => URL.revokeObjectURL(url));
        return merged.map((f) => URL.createObjectURL(f));
      });
      return merged;
    });
  };

  const submitUploadedPhotos = async () => {
    if (busyAction || trainingSetRunning) return;
    if (!name.trim() || uploadFiles.length < LORA_MIN_IMAGES) return;
    if (!uploadConsent || !uploadRightsConsent) {
      setError("Bitte best├ñtige beide Checkboxen, bevor es weitergeht.");
      return;
    }
    setError(null);
    setBusyAction("upload");
    setUploadProgress(0);

    const sessionId = crypto.randomUUID();
    let thumbnailPath: string | null = null;
    let uploadedCount = 0;

    try {
      for (let i = 0; i < uploadFiles.length; i++) {
        const formData = new FormData();
        formData.append("sessionId", sessionId);
        formData.append("index", String(i));
        formData.append("image", uploadFiles[i]!);

        const photoRes = await fetch("/api/ki-influencer/upload-photo", {
          method: "POST",
          body: formData,
        });
        const photoParsed = await parseKiInfluencerJsonResponse<UploadPhotoResponse>(
          photoRes
        );

        if (!photoParsed.ok || !photoParsed.data.success) {
          throw new Error(apiBodyToErrorMessage(photoParsed.data));
        }

        uploadedCount += 1;
        if (!thumbnailPath) thumbnailPath = photoParsed.data.storagePath;
        setUploadProgress(uploadedCount);
      }

      const createRes = await fetch("/api/ki-influencer/create-from-upload", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: name.trim(),
          sessionId,
          thumbnailPath,
          imageCount: uploadedCount,
        }),
      });
      const createParsed =
        await parseKiInfluencerJsonResponse<CreateFromUploadResponse>(createRes);
      const createData = createParsed.data;

      if (!isCreateFromUploadResponse(createData)) {
        throw new Error(apiBodyToErrorMessage(createData));
      }

      setCharacterId(createData.characterId);
      goToStep(2, { id: createData.characterId, name: name.trim() });
    } catch (err) {
      setWizardError(toErrorMessage(err));
    } finally {
      setBusyAction(null);
      setUploadProgress(0);
    }
  };

  const pollTrainingStatus = useCallback((id: string) => {
    if (pollRef.current) clearInterval(pollRef.current);
    pollRef.current = setInterval(async () => {
      try {
        const res = await fetch(`/api/ki-influencer/status/${id}`);
        const parsed = await parseKiInfluencerJsonResponse(res);
        const data = parsed.data as {
          progress?: number;
          logs?: string[];
          status?: string;
          errorMessage?: string;
        };
        if (typeof data.progress === "number") setLoraProgress(data.progress);
        if (Array.isArray(data.logs)) setLoraLogs(data.logs);
        if (data.status === "ready") {
          if (pollRef.current) clearInterval(pollRef.current);
          setCharacterReady(true);
          setBusyAction(null);
          goToStep(3);
        }
        if (data.status === "failed") {
          if (pollRef.current) clearInterval(pollRef.current);
          setWizardError(
            data.errorMessage ??
              "Das hat leider nicht geklappt. Bitte erneut versuchen."
          );
          setBusyAction(null);
        }
      } catch {
        /* keep polling */
      }
    }, 4000);
  }, [goToStep]);

  useEffect(() => {
    if (!characterId) return;

    let cancelled = false;

    void (async () => {
      try {
        const res = await fetch(`/api/ki-influencer/status/${characterId}`);
        const parsed = await parseKiInfluencerJsonResponse<
          KiInfluencerApiErrorBody & {
            status?: string;
            progress?: number;
            logs?: string[];
          }
        >(res);
        if (cancelled || !parsed.ok) return;

        const data = parsed.data;
        if (typeof data.progress === "number") {
          setLoraProgress(data.progress);
        }
        if (Array.isArray(data.logs)) {
          setLoraLogs(data.logs);
        }

        if (data.status === "training") {
          setBusyAction("loraTrain");
          pollTrainingStatus(characterId);
        } else if (data.status === "ready") {
          setCharacterReady(true);
          setBusyAction(null);
          goToStep(3);
        }
      } catch {
        /* ignore resume errors */
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [characterId, goToStep, pollTrainingStatus]);

  useEffect(() => {
    return () => {
      if (pollRef.current) clearInterval(pollRef.current);
    };
  }, []);

  const runCasting = async (confirm = false) => {
    if (busyAction || trainingSetRunning) return;
    setError(null);
    setBusyAction(confirm ? "castingConfirm" : "casting");
    try {
      const res = await fetch("/api/ki-influencer/casting", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          characterId: characterId ?? undefined,
          name,
          description,
          confirm,
        }),
      });
      const parsed = await parseKiInfluencerJsonResponse<
        KiInfluencerApiErrorBody & { characterId?: string; imageUrl?: string }
      >(res);
      const data = parsed.data;
      if (
        !confirm &&
        handleKiInfluencerApiError(
          parsed.status,
          data,
          IMAGE_GEN_CREDITS.standard
        )
      ) {
        return;
      }
      if (!parsed.ok || isKiInfluencerApiFailure(parsed.ok, data)) {
        throw new Error(apiBodyToErrorMessage(data));
      }
      if (data.characterId) {
        setCharacterId(data.characterId);
        persistWizardUrl({ id: data.characterId });
      }
      if (confirm) {
        setCastingConfirmed(true);
        goToStep(1, { id: data.characterId ?? characterId });
      } else if (data.imageUrl) {
        setCastingImageUrl(data.imageUrl);
      }
      window.dispatchEvent(new Event("credits-updated"));
    } catch (err) {
      setWizardError(toErrorMessage(err));
    } finally {
      setBusyAction(null);
    }
  };

  const runTrainingSet = async () => {
    if (!characterId || busyAction || trainingSetRunning) return;
    setError(null);
    setTrainingSetRunning(true);
    setTrainingProgress(0);

    try {
      const startRes = await fetch("/api/ki-influencer/training-set", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ characterId, start: true }),
      });
      const startParsed =
        await parseKiInfluencerJsonResponse<TrainingSetStartResponse>(
          startRes
        );
      const startData = startParsed.data;

      if (
        handleKiInfluencerApiError(
          startParsed.status,
          startData,
          KI_INFLUENCER_TRAINING_SET_CREDITS
        )
      ) {
        return;
      }

      if (!isTrainingSetStartResponse(startData)) {
        throw new Error(apiBodyToErrorMessage(startData));
      }

      window.dispatchEvent(new Event("credits-updated"));

      // Brief pause so character_set_id is visible before per-image requests.
      await new Promise((resolve) => setTimeout(resolve, 400));

      let successCount = 0;
      let lastError: string | null = null;

      for (let i = 0; i < KI_INFLUENCER_TRAINING_SET_SIZE; i++) {
        try {
          const res = await fetch("/api/ki-influencer/training-set", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ characterId, index: i }),
          });
          const parsed = await parseKiInfluencerJsonResponse<TrainingSetImageResponse>(
            res
          );
          const data = parsed.data;

          if (isTrainingSetImageResponse(data)) {
            successCount += 1;
            setTrainingProgress(successCount);
            continue;
          }

          if (
            handleKiInfluencerApiError(
              parsed.status,
              data,
              KI_INFLUENCER_TRAINING_SET_CREDITS
            )
          ) {
            return;
          }

          lastError = apiBodyToErrorMessage(data);
          console.warn("[ki-influencer] training-set image failed", i, data);
        } catch (imageErr) {
          lastError = toErrorMessage(imageErr);
          console.warn("[ki-influencer] training-set image error", i, imageErr);
        }
      }

      if (successCount >= LORA_MIN_IMAGES) {
        goToStep(2);
        return;
      }

      setWizardError(
        lastError ??
          `Es wurden nur ${successCount} von ${KI_INFLUENCER_TRAINING_SET_SIZE} Fotos erstellt ÔÇö mindestens ${LORA_MIN_IMAGES} n├Âtig.`
      );
    } catch (err) {
      setWizardError(toErrorMessage(err));
    } finally {
      setTrainingSetRunning(false);
    }
  };

  const runLoraTraining = async () => {
    if (!characterId || busyAction || trainingSetRunning) return;
    if (!consentAccepted) {
      setError("Bitte best├ñtige die Einwilligung, bevor es weitergeht.");
      return;
    }
    setError(null);
    setBusyAction("loraTrain");
    setLoraProgress(0);
    let startedPolling = false;
    try {
      if (pathMode === "uploaded") {
        const finRes = await fetch("/api/ki-influencer/finalize-upload", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ characterId }),
        });
        const finParsed =
          await parseKiInfluencerJsonResponse<FinalizeUploadResponse>(finRes);
        if (!finParsed.data.success) {
          throw new Error(apiBodyToErrorMessage(finParsed.data));
        }
      }

      const res = await fetch("/api/ki-influencer/train", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ characterId, consentAccepted: true }),
      });
      const parsed = await parseKiInfluencerJsonResponse<
        KiInfluencerApiErrorBody & { loraId?: string }
      >(res);
      const data = parsed.data;
      if (
        handleKiInfluencerApiError(parsed.status, data, loraTrainCredits)
      ) {
        return;
      }
      if (!parsed.ok || isKiInfluencerApiFailure(parsed.ok, data)) {
        throw new Error(apiBodyToErrorMessage(data));
      }
      window.dispatchEvent(new Event("credits-updated"));
      pollTrainingStatus(characterId);
      startedPolling = true;
    } catch (err) {
      setWizardError(toErrorMessage(err));
    } finally {
      if (!startedPolling) setBusyAction(null);
    }
  };

  const runContentGenerate = async () => {
    if (!characterId || !contentPrompt.trim() || busyAction || trainingSetRunning) {
      return;
    }
    setError(null);
    setBusyAction("content");
    setContentResultUrl(null);
    try {
      const res = await fetch("/api/ki-influencer/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          characterId,
          prompt: contentPrompt,
          styleId,
          platform,
        }),
      });
      const parsed = await parseKiInfluencerJsonResponse<
        KiInfluencerApiErrorBody & { imageUrl?: string }
      >(res);
      const data = parsed.data;
      if (
        handleKiInfluencerApiError(parsed.status, data, LORA_GENERATION_CREDIT)
      ) {
        return;
      }
      if (!parsed.ok || isKiInfluencerApiFailure(parsed.ok, data)) {
        throw new Error(apiBodyToErrorMessage(data));
      }
      if (data.imageUrl) setContentResultUrl(data.imageUrl);
      window.dispatchEvent(new Event("credits-updated"));
    } catch (err) {
      setWizardError(toErrorMessage(err));
    } finally {
      setBusyAction(null);
    }
  };

  const isUploading = busyAction === "upload";
  const isCasting = busyAction === "casting";
  const isCastingConfirm = busyAction === "castingConfirm";
  const isLoraTraining = busyAction === "loraTrain";
  const isContentGenerating = busyAction === "content";

  return (
    <div className="mx-auto max-w-[960px]">
      <div className="mb-8">
        <div className="mb-2 flex items-center gap-3">
          <UserRound size={32} color="#B4FF00" strokeWidth={2.2} />
          <h1 className="font-[family-name:var(--font-bebas)] text-[clamp(2rem,4vw,3rem)] tracking-wide text-[#F0EFE8]">
            KI-Influencer erstellen
          </h1>
        </div>
        <p className="text-[0.95rem] leading-relaxed text-[rgba(255,255,255,0.65)]">
          In 4 Schritten zu deinem eigenen KI-Influencer ÔÇö einmal einrichten, danach
          unbegrenzt Content erstellen.
        </p>
      </div>

      {error && (
        <p className="mb-4 text-sm text-[#ff6b7a]">
          {resolveWizardDisplayError(error, schemaReady)}
        </p>
      )}

      {pathMode === null && (
        <div className="mb-8 grid gap-4 sm:grid-cols-2">
          <button
            type="button"
            onClick={() => {
              setPathMode("generated");
              persistWizardUrl({ step: 0 });
            }}
