      );
      setFlowStep("input");
      stopPolling();
    }
  };

  const resetForm = () => {
    stopPolling();
    setFlowStep("input");
    setPhoto(null);
    setPhotoFile(null);
    setScript("");
    clearRecording();
    setVideoUrl(null);
    setVideoStatus("idle");
    setProgress(0);
    setError(null);
    setCreditsLeft(null);
    setAudioSource("own");
    setConsentAccepted(false);
    setVoiceId(getDefaultVoiceIdForLocale(locale));
