  const handleVoiceSelect = (voice: ElevenLabsVoice) => {
    setVoiceId(voice.id);
  };

  return (
    <div className="max-w-xl mx-auto pb-16 px-1">
      {!embedded && (
        <header className="mb-6">
          <p className="text-[#B4FF00] text-[0.7rem] font-bold uppercase tracking-[0.14em] mb-2">
