          </p>
          <h1 className="font-[family-name:var(--font-bebas)] text-4xl text-[#F0EFE8] leading-tight mb-2">
            AVATAR VIDEO
          </h1>
          <p className="text-white/80 text-sm">
            Lade ein Foto hoch und lass es sprechen ÔÇö InfluexAI Talking Avatar ┬À{" "}
            {CREDIT_COST} Credits
          </p>
        </header>
      )}

      {flowStep === "input" && (
        <StepIndicator
          photoReady={photoReady}
          audioReady={audioReady}
          isGenerating={false}
          isResult={false}
        />
      )}

      {error && (
        <div
