            {/* STEP 2: Audio */}
            <section className="space-y-4">
              <h2 className="text-white/80 text-xs uppercase tracking-wider font-bold">
                Schritt 2 ┬À Audio
              </h2>
              <p className="text-white/80 text-sm uppercase tracking-wider">
                Audio-Quelle w├ñhlen
              </p>

              <div className="grid grid-cols-2 gap-3">
                <button
                  type="button"
                  onClick={() => setAudioSource("own")}
                  className={`p-4 rounded-xl border-2 text-left transition-all ${
                    audioSource === "own"
                      ? "border-[#B4FF00] bg-[#B4FF00]/10"
                      : "border-white/10 bg-white/5 hover:border-white/30"
                  }`}
                >
                  <div className="text-2xl mb-2">­ƒÄñ</div>
                  <p
                    className={`font-semibold text-sm ${
                      audioSource === "own" ? "text-[#B4FF00]" : "text-white"
                    }`}
                  >
                    Eigene Stimme
                  </p>
                  <p className="text-white/70 text-xs mt-1">
                    Authentischer & pers├Ânlicher
                  </p>
                </button>
                <button
                  type="button"
                  onClick={() => setAudioSource("elevenlabs")}
                  className={`p-4 rounded-xl border-2 text-left transition-all ${
                    audioSource === "elevenlabs"
                      ? "border-[#B4FF00] bg-[#B4FF00]/10"
                      : "border-white/10 bg-white/5 hover:border-white/30"
                  }`}
                >
                  <div className="text-2xl mb-2">­ƒñû</div>
                  <p
                    className={`font-semibold text-sm ${
                      audioSource === "elevenlabs"
                        ? "text-[#B4FF00]"
                        : "text-white"
                    }`}
                  >
                    KI-Stimme
                  </p>
                  <p className="text-white/70 text-xs mt-1">
                    ElevenLabs ┬À Professionell
                  </p>
                </button>
              </div>

              <div>
                <label className="text-white/80 text-xs uppercase tracking-wider mb-2 block font-bold">
                  Dein Script
                </label>
                <textarea
                  value={script}
                  onChange={(e) =>
                    setScript(e.target.value.slice(0, 500))
                  }
                  placeholder="Was soll dein Avatar sagen? z.B. Hey, willkommen auf meinem KanalÔÇª"
                  rows={4}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white placeholder-white/20 text-sm resize-none focus:outline-none focus:border-[#B4FF00]/50 transition-all"
                />
                <div className="flex justify-between mt-1">
                  <span className="text-white/20 text-xs">
                    Tipp: 50ÔÇô200 W├Ârter f├╝r beste Ergebnisse
                  </span>
                  <span className="text-white/65 text-xs">
                    {script.length}/500
                  </span>
                </div>
              </div>

              {audioSource === "own" && (
                <div className="bg-white/5 rounded-xl p-4 border border-white/10">
                  <p className="text-white/80 text-xs uppercase tracking-wider mb-3 font-bold">
                    Stimme aufnehmen
                  </p>
                  {!recordedBlob ? (
                    <div className="flex flex-col items-center gap-3 py-4">
                      <button
                        type="button"
                        onClick={
                          isRecording ? stopRecording : startRecording
                        }
                        className={`w-16 h-16 rounded-full flex items-center justify-center text-2xl transition-all active:scale-95 ${
                          isRecording
                            ? "bg-red-500 animate-pulse shadow-lg shadow-red-500/30"
                            : "bg-[#B4FF00] hover:bg-[#c8ff33] shadow-lg shadow-[#B4FF00]/20 text-[#060608]"
                        }`}
                      >
                        {isRecording ? "ÔÅ╣" : "­ƒÄñ"}
                      </button>
                      <p className="text-white/70 text-sm">
                        {isRecording
                          ? "ÔùÅ Aufnahme l├ñuftÔÇª"
                          : "Zum Aufnehmen klicken"}
                      </p>
                      {isRecording && (
                        <div className="flex gap-1 items-end h-6">
                          {WAVE_HEIGHTS.map((h, i) => (
                            <div
                              key={i}
                              className="w-1 bg-[#B4FF00] rounded-full animate-bounce"
                              style={{
                                height: `${h}px`,
                                animationDelay: `${i * 0.1}s`,
                              }}
                            />
                          ))}
                        </div>
                      )}
                    </div>
                  ) : (
                    <div className="space-y-3">
                      {recordedUrl && (
                        <audio
                          controls
                          src={recordedUrl}
                          className="w-full h-10"
                        />
                      )}
                      <button
                        type="button"
                        onClick={clearRecording}
                        className="text-white/70 text-xs hover:text-white transition-colors"
                      >
                        Ôå║ Neu aufnehmen
                      </button>
                    </div>
                  )}
                </div>
              )}

              {audioSource === "elevenlabs" && (
                <div className="bg-white/5 rounded-xl p-4 border border-white/10">
                  <p className="text-white/80 text-xs uppercase tracking-wider mb-3 font-bold">
                    Stimme w├ñhlen
                  </p>
                  <LiveCreatorVoicePicker
                    selectedVoiceId={voiceId}
                    onVoiceSelect={handleVoiceSelect}
                  />
                </div>
              )}
            </section>

            {/* STEP 3: Generate */}
            <section className="space-y-4 pt-2 border-t border-white/[0.06]">
              <h2 className="text-white/80 text-xs uppercase tracking-wider font-bold">
                Schritt 3 ┬À Generieren
              </h2>
              <label className="flex items-start gap-3 rounded-xl border border-white/10 bg-white/5 p-4 cursor-pointer">
                <input
                  type="checkbox"
                  checked={consentAccepted}
                  onChange={(e) => setConsentAccepted(e.target.checked)}
                  className="mt-0.5 h-4 w-4 shrink-0 accent-[#B4FF00]"
                />
                <span className="text-sm text-white/75 leading-relaxed">
                  Ich best├ñtige, dass ich nur eigenes oder lizenziertes
                  Bildmaterial verwende und der Erstellung eines Talking-Avatar-Videos
                  ausdr├╝cklich zustimme.
                </span>
              </label>
              <button
                type="button"
                onClick={handleGenerate}
                disabled={!canGenerate}
                className={`w-full py-4 rounded-xl font-semibold text-lg transition-all duration-300 ${
                  canGenerate
                    ? "bg-[#B4FF00] text-[#060608] hover:bg-[#c8ff33] active:scale-[0.98] shadow-lg shadow-[#B4FF00]/15"
                    : "bg-white/10 text-white/65 cursor-not-allowed"
                }`}
              >
                {isGenerating
                  ? "ÔÅ│ Wird generiertÔÇª"
                  : `­ƒÄ¼ Avatar-Video erstellen ┬À ${CREDIT_COST} Credits`}
              </button>
              <div className="flex gap-6 justify-center text-xs">
                <span
                  className={photoReady ? "text-[#B4FF00]" : "text-white/20"}
                >
                  {photoReady ? "Ô£ô" : "Ôùï"} Foto
                </span>
                <span
                  className={scriptReady ? "text-[#B4FF00]" : "text-white/20"}
                >
                  {scriptReady ? "Ô£ô" : "Ôùï"} Script
                </span>
                <span
                  className={
                    audioSource === "own"
                      ? recordedBlob
                        ? "text-[#B4FF00]"
                        : "text-white/20"
                      : voiceId && scriptReady
                        ? "text-[#B4FF00]"
                        : "text-white/20"
                  }
                >
                  {(audioSource === "own" ? recordedBlob : voiceId)
                    ? "Ô£ô"
                    : "Ôùï"}{" "}
                  Audio
                </span>
              </div>
            </section>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect, useCallback, type CSSProperties } from "react";

export default function LivePortraitPage() {
  const [sourceImage, setSourceImage] = useState<string | null>(null);
  const [sourceImageFile, setSourceImageFile] = useState<File | null>(null);
  const [drivingVideo, setDrivingVideo] = useState<string | null>(null);
  const [drivingVideoFile, setDrivingVideoFile] = useState<File | null>(null);
  const [videoMode, setVideoMode] = useState<"upload" | "webcam">("upload");
  const [recording, setRecording] = useState(false);
  const [countdown, setCountdown] = useState<number | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [creditsLeft, setCreditsLeft] = useState<number | null>(null);
  const [consentAccepted, setConsentAccepted] = useState(false);

  const imageRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const webcamRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const drivingVideoUrlRef = useRef<string | null>(null);

  const setDrivingVideoPreview = useCallback((url: string | null) => {
    if (drivingVideoUrlRef.current) {
      URL.revokeObjectURL(drivingVideoUrlRef.current);
      drivingVideoUrlRef.current = null;
    }
    if (url) drivingVideoUrlRef.current = url;
    setDrivingVideo(url);
  }, []);

  const stopWebcam = useCallback(() => {
    streamRef.current?.getTracks().forEach((t) => t.stop());
    streamRef.current = null;
    if (webcamRef.current) {
      webcamRef.current.srcObject = null;
    }
  }, []);

  const startWebcam = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: 640, height: 480, facingMode: "user" },
        audio: false,
      });
      streamRef.current = stream;
      if (webcamRef.current) {
        webcamRef.current.srcObject = stream;
        await webcamRef.current.play();
      }
    } catch {
      setError("Kamera-Zugriff verweigert. Bitte Kamera erlauben.");
    }
  }, []);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current?.state === "recording") {
      mediaRecorderRef.current.stop();
    }
  }, []);

  const startRecording = useCallback(async () => {
    if (!streamRef.current) return;

    setCountdown(3);
    await new Promise<void>((resolve) => {
      let c = 3;
      const interval = setInterval(() => {
        c--;
        setCountdown(c);
        if (c <= 0) {
          clearInterval(interval);
          setCountdown(null);
          resolve();
        }
      }, 1000);
    });

    chunksRef.current = [];
    const mimeType = MediaRecorder.isTypeSupported("video/webm;codecs=vp8")
      ? "video/webm;codecs=vp8"
      : "video/webm";
    const mr = new MediaRecorder(streamRef.current, { mimeType });
    mr.ondataavailable = (e) => {
      if (e.data.size > 0) chunksRef.current.push(e.data);
    };
    mr.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: mimeType });
      const file = new File([blob], "webcam.webm", { type: mimeType });
      setDrivingVideoFile(file);
      setDrivingVideoPreview(URL.createObjectURL(blob));
      setRecording(false);
    };
    mediaRecorderRef.current = mr;
    mr.start();
    setRecording(true);

    setTimeout(() => {
      if (mr.state === "recording") mr.stop();
    }, 10000);
  }, [setDrivingVideoPreview]);

  useEffect(() => {
    return () => {
      stopWebcam();
      if (mediaRecorderRef.current?.state === "recording") {
        mediaRecorderRef.current.stop();
      }
      if (drivingVideoUrlRef.current) {
        URL.revokeObjectURL(drivingVideoUrlRef.current);
      }
    };
  }, [stopWebcam]);

  const toBase64 = (file: File): Promise<string> =>
    new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

