"use client";

import { Suspense, useCallback, useEffect, useRef, useState } from "react";
import { useTranslations } from "next-intl";
import {
  Box,
  Bot,
  Brain,
  Brush,
  Copy,
  User,
  Check,
} from "lucide-react";
import { UseLoraModal } from "@/components/lora/UseLoraModal";
import { sanitizeUserMessage } from "@/lib/sanitize-user-message";
import { AiOutputDisclaimer } from "@/components/ui/AiOutputDisclaimer";
import { calcLoraCredits } from "@/lib/lora-credits";
import {
  LORA_ESTIMATED_MINUTES,
  LORA_MAX_IMAGES,
  LORA_MIN_IMAGES,
  LORA_RECOMMENDED_IMAGES,
  LORA_STEPS_DEFAULT,
  LORA_STEPS_MAX,
  LORA_STEPS_MIN,
  LORA_STORAGE_BUCKET,
  LORA_TYPE_META,
  TRIGGER_WORD_PRESETS,
  type LoraModelType,
} from "@/lib/lora-config";
import { createClient } from "@/lib/supabase/client";

type Step = "setup" | "training" | "done";

type LoraRow = {
  id: string;
  name: string;
  trigger_word: string;
  type: LoraModelType;
  status: string;
  lora_url: string | null;
  thumbnail_url: string | null;
  training_images_count: number | null;
  steps: number;
  progress: number | null;
  error_message: string | null;
  created_at: string;
};

const TYPE_ICONS: Record<LoraModelType, typeof User> = {
  portrait: User,
  style: Brush,
  product: Box,
  character: Bot,
};

function card() {
  return {
    padding: 24,
    borderRadius: 16,
    background: "#0f0f12",
    border: "1px solid rgba(255,255,255,0.07)",
  } as const;
}

function LoraTrainingPageInner() {
  const t = useTranslations("flows.loraTraining");
  const [step, setStep] = useState<Step>("setup");
  const [trainType, setTrainType] = useState<LoraModelType>("portrait");
  const [files, setFiles] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);
  const [modelName, setModelName] = useState("");
  const [triggerWord, setTriggerWord] = useState("MYFACE");
  const [trainingSteps, setTrainingSteps] = useState(LORA_STEPS_DEFAULT);
  const [isStyle, setIsStyle] = useState(false);
  const [dragOver, setDragOver] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeLoraId, setActiveLoraId] = useState<string | null>(null);
  const [progress, setProgress] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const [models, setModels] = useState<LoraRow[]>([]);
  const [thumbUrls, setThumbUrls] = useState<Record<string, string>>({});
  const [useModalLora, setUseModalLora] = useState<LoraRow | null>(null);
  const [copied, setCopied] = useState<string | null>(null);
  const [consentAccepted, setConsentAccepted] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const creditCost = calcLoraCredits(trainingSteps);

  const loadModels = useCallback(async () => {
    const supabase = createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) return;

    const { data } = await supabase
      .from("lora_models")
      .select("*")
      .eq("user_id", user.id)
      .order("created_at", { ascending: false });

    if (data) {
      setModels(data as LoraRow[]);
      const urls: Record<string, string> = {};
      for (const m of data) {
        if (m.thumbnail_url) {
          const { data: signed } = await supabase.storage
            .from(LORA_STORAGE_BUCKET)
            .createSignedUrl(m.thumbnail_url, 3600);
          if (signed?.signedUrl) urls[m.id] = signed.signedUrl;
        }
      }
      setThumbUrls(urls);
    }
  }, []);

  useEffect(() => {
    loadModels();
  }, [loadModels]);

  useEffect(() => {
    setIsStyle(trainType === "style");
    if (trainType === "portrait") setTriggerWord("MYFACE");
    if (trainType === "style") setTriggerWord("MYSTYLE");
    if (trainType === "product") setTriggerWord("MYPRODUCT");
    if (trainType === "character") setTriggerWord("MYCHAR");
  }, [trainType]);

  const addFiles = (incoming: FileList | File[]) => {
    const list = Array.from(incoming).filter((f) =>
      f.type.startsWith("image/")
    );
    const merged = [...files, ...list].slice(0, LORA_MAX_IMAGES);
    setFiles(merged);
    setPreviews((prev) => {
      prev.forEach((u) => URL.revokeObjectURL(u));
      return merged.map((f) => URL.createObjectURL(f));
    });
  };

  const pollStatus = useCallback(
    (loraId: string) => {
      if (pollRef.current) clearInterval(pollRef.current);
      pollRef.current = setInterval(async () => {
        try {
          const res = await fetch(`/api/lora/status/${loraId}`);
          const data = await res.json();
          if (data.progress != null) setProgress(data.progress);
          if (Array.isArray(data.logs)) setLogs(data.logs);
          if (data.status === "ready") {
            if (pollRef.current) clearInterval(pollRef.current);
            setStep("done");
            setLoading(false);
            loadModels();
          }
          if (data.status === "failed") {
            if (pollRef.current) clearInterval(pollRef.current);
            setError(data.errorMessage ?? t("error_training_failed"));
            setStep("setup");
            setLoading(false);
            loadModels();
          }
        } catch {
          /* keep polling */
        }
      }, 4000);
    },
    [loadModels, t]
  );

  useEffect(() => {
    return () => {
      if (pollRef.current) clearInterval(pollRef.current);
      previews.forEach((u) => URL.revokeObjectURL(u));
    };
  }, [previews]);

  const startTraining = async () => {
    if (files.length < LORA_MIN_IMAGES) {
      setError(t("error_min_images", { min: LORA_MIN_IMAGES }));
      return;
    }
    if (!modelName.trim() || !triggerWord.trim()) {
      setError(t("error_missing_fields"));
      return;
    }
    if (!consentAccepted) {
      setError(
        "Bitte best├ñtige die Einwilligung, bevor das Training startet."
      );
      return;
    }

    setError(null);
    setLoading(true);
    setStep("training");
    setProgress(0);
    setLogs([]);

    try {
      const formData = new FormData();
      files.forEach((f) => formData.append("images", f));
      formData.append("consentAccepted", "true");

      const uploadRes = await fetch("/api/lora/upload", {
        method: "POST",
        body: formData,
      });
      const uploadData = await uploadRes.json();
      if (!uploadRes.ok) throw new Error(uploadData.error ?? t("error_upload"));

      const trainRes = await fetch("/api/lora/train", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: modelName.trim(),
          triggerWord: triggerWord.trim(),
          type: trainType,
          zipUrl: uploadData.zipUrl,
          sessionId: uploadData.sessionId,
          thumbnailPath: uploadData.thumbnailPath,
          imageCount: uploadData.imageCount,
          steps: trainingSteps,
          isStyle: trainType === "style" ? isStyle : false,
          consentAccepted: true,
        }),
      });
      const trainData = await trainRes.json();
      if (!trainRes.ok) throw new Error(trainData.error ?? t("error_generic"));

      setActiveLoraId(trainData.loraId);
      pollStatus(trainData.loraId);
      window.dispatchEvent(new Event("credits-updated"));
      loadModels();
    } catch (err) {
      setError(
        sanitizeUserMessage(err instanceof Error ? err.message : t("error_generic"))
      );
      setStep("setup");
      setLoading(false);
    }
  };

  const deleteModel = async (id: string) => {
    if (!confirm(t("delete_confirm"))) return;
    const res = await fetch("/api/lora/delete", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id }),
    });
    if (res.ok) loadModels();
  };

  const copyTrigger = (word: string, id: string) => {
    navigator.clipboard.writeText(word);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  const resetForm = () => {
    setStep("setup");
    setActiveLoraId(null);
    setProgress(0);
    setLogs([]);
    setLoading(false);
  };

  return (
    <div style={{ maxWidth: 960, margin: "0 auto", padding: "0 4px" }}>
      <div style={{ marginBottom: 28, display: "flex", alignItems: "flex-start", gap: 12, flexWrap: "wrap" }}>
        <div style={{ flex: 1 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
            <Brain size={28} color="#B4FF00" />
            <h1
              style={{
                fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif",
                fontSize: "clamp(2rem, 4vw, 3rem)",
                letterSpacing: "0.02em",
                color: "#F0EFE8",
                margin: 0,
              }}
            >
              {t("title")}
            </h1>
            <span
              style={{
                padding: "4px 10px",
                borderRadius: 99,
                background: "rgba(180,255,0,0.15)",
                color: "#B4FF00",
                fontSize: "0.65rem",
                fontWeight: 800,
                letterSpacing: "0.12em",
              }}
            >
              BETA
            </span>
          </div>
          <p style={{ color: "rgba(255,255,255,0.65)", fontSize: "0.9rem", margin: 0 }}>{t("description")}</p>
        </div>
      </div>

      {error && (
        <div
          style={{
            marginBottom: 16,
            padding: "12px 16px",
            borderRadius: 10,
            background: "rgba(239,68,68,0.1)",
            border: "1px solid rgba(239,68,68,0.3)",
            color: "#fca5a5",
            fontSize: "0.88rem",
          }}
        >
          {error}
        </div>
      )}

      {/* Demo */}
      <div style={{ ...card(), marginBottom: 16 }}>
        <div style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", marginBottom: 12, letterSpacing: "0.08em", textTransform: "uppercase" }}>
          {t("demo_title")}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 12 }}>
          <div style={{ padding: 16, borderRadius: 12, background: "#18181d", textAlign: "center" }}>
            <div style={{ fontSize: "0.75rem", color: "rgba(255,255,255,0.65)", marginBottom: 8 }}>{t("demo_without")}</div>
            <div style={{ height: 120, borderRadius: 8, background: "linear-gradient(135deg,#2a2a2a,#1a1a1a)", display: "flex", alignItems: "center", justifyContent: "center", color: "rgba(255,255,255,0.65)", fontSize: "0.85rem" }}>
              Generic AI
            </div>
          </div>
          <div style={{ padding: 16, borderRadius: 12, background: "rgba(180,255,0,0.06)", border: "1px solid rgba(180,255,0,0.2)", textAlign: "center" }}>
            <div style={{ fontSize: "0.75rem", color: "#B4FF00", marginBottom: 8 }}>{t("demo_with")}</div>
            <div style={{ height: 120, borderRadius: 8, background: "linear-gradient(135deg,#1a2a0a,#0f0f12)", display: "flex", alignItems: "center", justifyContent: "center", color: "#B4FF00", fontSize: "0.85rem" }}>
              MYFACE in new scene Ô£ô
            </div>
          </div>
        </div>
      </div>

      {step === "setup" && (
        <>
          {/* Type cards */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 12, marginBottom: 16 }}>
            {(Object.keys(LORA_TYPE_META) as LoraModelType[]).map((type) => {
              const meta = LORA_TYPE_META[type];
              const Icon = TYPE_ICONS[type];
              const selected = trainType === type;
              return (
                <button
                  key={type}
                  type="button"
                  onClick={() => setTrainType(type)}
                  style={{
                    ...card(),
                    cursor: "pointer",
                    textAlign: "left",
                    border: `1px solid ${selected ? "rgba(180,255,0,0.45)" : "rgba(255,255,255,0.07)"}`,
                    background: selected ? "rgba(180,255,0,0.06)" : "#0f0f12",
                    minHeight: 44,
                  }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                    <Icon size={20} color={selected ? "#B4FF00" : "rgba(255,255,255,0.65)"} />
                    <span style={{ fontWeight: 700, color: "#F0EFE8" }}>{t(`type_${type}`)}</span>
                    {meta.recommended && (
                      <span style={{ marginLeft: "auto", fontSize: "0.65rem", color: "#B4FF00", fontWeight: 800 }}>Ô£ô {t("recommended")}</span>
                    )}
                  </div>
                  <p style={{ margin: 0, fontSize: "0.8rem", color: "rgba(255,255,255,0.65)", lineHeight: 1.5 }}>{t(`type_${type}_desc`)}</p>
                </button>
              );
            })}
          </div>

          {/* Upload */}
          <div style={{ ...card(), marginBottom: 16 }}>
            <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 10, letterSpacing: "0.08em", textTransform: "uppercase" }}>
              {t("upload_label")} ({files.length}/{LORA_MAX_IMAGES})
            </label>
            <div
              onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
              onDragLeave={() => setDragOver(false)}
              onDrop={(e) => { e.preventDefault(); setDragOver(false); addFiles(e.dataTransfer.files); }}
              onClick={() => fileRef.current?.click()}
              style={{
                border: `2px dashed ${dragOver ? "#B4FF00" : "rgba(255,255,255,0.12)"}`,
                borderRadius: 12,
                padding: previews.length ? 12 : 28,
                textAlign: "center",
                cursor: "pointer",
                background: dragOver ? "rgba(180,255,0,0.05)" : "#18181d",
                minHeight: 100,
              }}
            >
              <input ref={fileRef} type="file" accept="image/jpeg,image/png,image/webp" multiple hidden onChange={(e) => e.target.files && addFiles(e.target.files)} />
              {previews.length ? (
                <div style={{ display: "flex", flexWrap: "wrap", gap: 8, justifyContent: "center" }}>
                  {previews.slice(0, 12).map((src, i) => (
                    <img key={i} src={src} alt="" style={{ width: 56, height: 56, objectFit: "cover", borderRadius: 6 }} />
                  ))}
                  {previews.length > 12 && <span style={{ color: "rgba(255,255,255,0.65)", alignSelf: "center" }}>+{previews.length - 12}</span>}
                </div>
              ) : (
                <p style={{ color: "rgba(255,255,255,0.65)", margin: 0 }}>{t("upload_drop")}</p>
              )}
            </div>
            <p style={{ fontSize: "0.75rem", color: "rgba(255,255,255,0.65)", marginTop: 10, lineHeight: 1.6 }}>
              {t("upload_rules", { min: LORA_MIN_IMAGES, rec: LORA_RECOMMENDED_IMAGES, max: LORA_MAX_IMAGES })}
            </p>
            <p style={{ fontSize: "0.75rem", color: "#B4FF00", marginTop: 6, opacity: 0.85 }}>{t(LORA_TYPE_META[trainType].tipKey)}</p>
          </div>

          {/* Settings */}
          <div style={{ ...card(), marginBottom: 16, display: "flex", flexDirection: "column", gap: 14 }}>
            <div>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 8 }}>{t("name_label")}</label>
              <input value={modelName} onChange={(e) => setModelName(e.target.value)} placeholder={t("name_placeholder")} style={{ width: "100%", padding: "14px 16px", minHeight: 48, borderRadius: 10, background: "#18181d", border: "1px solid rgba(255,255,255,0.09)", color: "#F0EFE8", fontSize: "16px" }} />
            </div>
            <div>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 8 }}>{t("trigger_label")}</label>
              <input value={triggerWord} onChange={(e) => setTriggerWord(e.target.value.toUpperCase())} placeholder="MYFACE" style={{ width: "100%", padding: "14px 16px", minHeight: 48, borderRadius: 10, background: "#18181d", border: "1px solid rgba(255,255,255,0.09)", color: "#B4FF00", fontSize: "16px", fontWeight: 700, letterSpacing: "0.06em" }} />
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 8 }}>
                {TRIGGER_WORD_PRESETS.map((p) => (
                  <button key={p} type="button" onClick={() => setTriggerWord(p)} style={{ padding: "4px 10px", borderRadius: 99, border: "1px solid rgba(180,255,0,0.25)", background: triggerWord === p ? "rgba(180,255,0,0.12)" : "transparent", color: "#B4FF00", fontSize: "0.72rem", cursor: "pointer", minHeight: 32 }}>{p}</button>
                ))}
              </div>
              <p style={{ fontSize: "0.72rem", color: "rgba(255,255,255,0.65)", marginTop: 8 }}>{t("trigger_hint")}</p>
            </div>
            <div>
              <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", gap: 12, marginBottom: 8, flexWrap: "wrap" }}>
                <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)" }}>
                  {t("steps_label")}: {trainingSteps}
                </label>
                <span style={{ fontSize: "0.78rem", fontWeight: 700, color: "#B4FF00" }}>
                  {creditCost} Credits
                </span>
              </div>
              <input type="range" min={LORA_STEPS_MIN} max={LORA_STEPS_MAX} step={100} value={trainingSteps} onChange={(e) => setTrainingSteps(Number(e.target.value))} style={{ width: "100%", accentColor: "#B4FF00" }} />
              <p style={{ fontSize: "0.72rem", color: "rgba(255,255,255,0.65)", marginTop: 6 }}>{t("steps_hint")}</p>
            </div>
            {trainType === "style" && (
              <label style={{ display: "flex", alignItems: "center", gap: 10, cursor: "pointer", minHeight: 44 }}>
                <input type="checkbox" checked={isStyle} onChange={(e) => setIsStyle(e.target.checked)} style={{ width: 18, height: 18, accentColor: "#B4FF00" }} />
                <span style={{ color: "#F0EFE8", fontSize: "0.88rem" }}>{t("style_toggle")}</span>
              </label>
            )}
          </div>

          <p
            style={{
              textAlign: "center",
              color: "#B4FF00",
              fontWeight: 700,
              fontSize: "0.9rem",
              marginBottom: 10,
            }}
          >
            {t("cost_preview", { credits: creditCost })}
          </p>

          <label
            style={{
              display: "flex",
              alignItems: "flex-start",
              gap: 12,
              padding: 16,
              marginBottom: 16,
              borderRadius: 12,
              border: "1px solid rgba(255,255,255,0.1)",
              background: "rgba(255,255,255,0.03)",
              cursor: "pointer",
            }}
          >
            <input
              type="checkbox"
              checked={consentAccepted}
              onChange={(e) => setConsentAccepted(e.target.checked)}
              style={{
                marginTop: 2,
                accentColor: "#B4FF00",
                width: 16,
                height: 16,
                flexShrink: 0,
              }}
            />
            <span
              style={{
                fontSize: "0.82rem",
                color: "rgba(255,255,255,0.85)",
                lineHeight: 1.5,
              }}
            >
              Ich habe die Rechte und Einwilligung f├╝r alle Trainingsbilder. Ich
              lade keine Bilder anderer Personen ohne deren Zustimmung hoch. Ich
              verstehe, dass daraus ein KI-Trainingsmodell entstehen kann.
            </span>
          </label>

          <button
            type="button"
            onClick={startTraining}
            disabled={loading || files.length < LORA_MIN_IMAGES || !consentAccepted}
            style={{
              width: "100%",
              padding: "15px",
              borderRadius: 12,
              border: "none",
              background:
                files.length >= LORA_MIN_IMAGES && consentAccepted
                  ? "#B4FF00"
                  : "#2a2a2a",
              color:
                files.length >= LORA_MIN_IMAGES && consentAccepted
                  ? "#060608"
                  : "rgba(255,255,255,0.65)",
              fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif",
              fontSize: "1.3rem",
              letterSpacing: "0.04em",
              cursor:
                files.length >= LORA_MIN_IMAGES && consentAccepted
                  ? "pointer"
                  : "default",
              minHeight: 52,
              marginBottom: 8,
            }}
          >
            {t("start_button", { credits: creditCost })}
          </button>
          <p style={{ textAlign: "center", color: "rgba(255,255,255,0.65)", fontSize: "0.8rem", marginBottom: 24 }}>{t("estimated_time", { time: LORA_ESTIMATED_MINUTES })}</p>
        </>
      )}

      {step === "training" && (
        <div style={{ ...card(), textAlign: "center", padding: "48px 24px", marginBottom: 24 }}>
          <div style={{ width: 64, height: 64, borderRadius: "50%", border: "3px solid #B4FF00", borderTopColor: "transparent", animation: "spin 0.8s linear infinite", margin: "0 auto 20px" }} />
          <h2 style={{ fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif", fontSize: "1.6rem", color: "#F0EFE8", marginBottom: 8 }}>{t("training_title")}</h2>
          <p style={{ color: "rgba(255,255,255,0.65)", fontSize: "0.88rem", marginBottom: 20 }}>{t("training_subtitle")}</p>
          <div style={{ height: 8, borderRadius: 99, background: "#18181d", overflow: "hidden", maxWidth: 400, margin: "0 auto 12px" }}>
            <div style={{ height: "100%", width: `${Math.max(progress, 5)}%`, background: "#B4FF00", transition: "width 0.4s" }} />
          </div>
          <p style={{ color: "#B4FF00", fontWeight: 700, marginBottom: 16 }}>{progress}%</p>
          {logs.length > 0 && (
            <div style={{ textAlign: "left", maxWidth: 420, margin: "0 auto", padding: 12, borderRadius: 8, background: "#18181d", fontSize: "0.72rem", color: "rgba(255,255,255,0.65)", fontFamily: "monospace", maxHeight: 120, overflow: "auto" }}>
              {logs.map((l, i) => <div key={i}>{l}</div>)}
            </div>
          )}
          <button type="button" onClick={resetForm} style={{ marginTop: 20, padding: "8px 16px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.09)", background: "transparent", color: "rgba(255,255,255,0.65)", cursor: "pointer" }}>
            {t("training_background")}
          </button>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
      )}

      {step === "done" && (
        <div style={{ ...card(), textAlign: "center", padding: 32, marginBottom: 24, border: "1px solid rgba(180,255,0,0.3)" }}>
          <Check size={40} color="#B4FF00" style={{ margin: "0 auto 12px" }} />
          <h2 style={{ fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif", fontSize: "1.6rem", color: "#F0EFE8" }}>{t("done_title")}</h2>
          <p style={{ color: "rgba(255,255,255,0.65)", marginBottom: 16 }}>{t("done_subtitle")}</p>
          <button type="button" onClick={resetForm} style={{ padding: "12px 20px", borderRadius: 10, border: "none", background: "#B4FF00", color: "#060608", fontWeight: 700, cursor: "pointer" }}>{t("done_button")}</button>
          <AiOutputDisclaimer className="mt-4" />
        </div>
      )}

      {/* My models */}
      <div style={card()}>
        <h2 style={{ fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif", fontSize: "1.4rem", color: "#F0EFE8", marginBottom: 16 }}>{t("models_title")}</h2>
        {models.length === 0 ? (
          <p style={{ color: "rgba(255,255,255,0.65)", fontSize: "0.88rem" }}>{t("models_empty")}</p>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {models.map((m) => (
              <div key={m.id} style={{ display: "flex", gap: 14, padding: 14, borderRadius: 12, background: "#18181d", flexWrap: "wrap", alignItems: "center" }}>
                <div style={{ width: 56, height: 56, borderRadius: 8, overflow: "hidden", background: "#0f0f12", flexShrink: 0 }}>
                  {thumbUrls[m.id] ? <img src={thumbUrls[m.id]} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", color: "rgba(255,255,255,0.65)", fontSize: "1.2rem" }}>­ƒºá</div>}
                </div>
                <div style={{ flex: 1, minWidth: 140 }}>
                  <div style={{ fontWeight: 700, color: "#F0EFE8" }}>{m.name}</div>
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 4 }}>
                    <code style={{ color: "#B4FF00", fontSize: "0.78rem" }}>{m.trigger_word}</code>
                    <button type="button" onClick={() => copyTrigger(m.trigger_word, m.id)} style={{ background: "none", border: "none", cursor: "pointer", padding: 0, color: "rgba(255,255,255,0.65)" }}>
                      {copied === m.id ? <Check size={14} color="#B4FF00" /> : <Copy size={14} />}
                    </button>
                  </div>
                  <div style={{ display: "flex", gap: 8, marginTop: 6, flexWrap: "wrap" }}>
                    <span style={{ fontSize: "0.65rem", padding: "2px 8px", borderRadius: 99, background: "rgba(255,255,255,0.06)", color: "rgba(255,255,255,0.65)" }}>{t(`type_${m.type}`)}</span>
                    <span style={{ fontSize: "0.65rem", padding: "2px 8px", borderRadius: 99, background: m.status === "ready" ? "rgba(180,255,0,0.12)" : m.status === "failed" ? "rgba(239,68,68,0.12)" : "rgba(255,255,255,0.06)", color: m.status === "ready" ? "#B4FF00" : m.status === "failed" ? "#fca5a5" : "rgba(255,255,255,0.65)" }}>
                      {t(`status_${m.status}`)}
                    </span>
                  </div>
                </div>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  {m.status === "ready" && (
                    <button type="button" onClick={() => setUseModalLora(m)} style={{ padding: "8px 14px", borderRadius: 8, border: "none", background: "#B4FF00", color: "#060608", fontWeight: 700, cursor: "pointer", minHeight: 40 }}>{t("use_button")}</button>
                  )}
                  {m.status === "training" && activeLoraId !== m.id && (
                    <button type="button" onClick={() => { setActiveLoraId(m.id); setStep("training"); pollStatus(m.id); }} style={{ padding: "8px 14px", borderRadius: 8, border: "1px solid rgba(180,255,0,0.35)", background: "transparent", color: "#B4FF00", cursor: "pointer", minHeight: 40 }}>{t("view_progress")}</button>
                  )}
                  <button type="button" onClick={() => deleteModel(m.id)} disabled={m.status === "training"} style={{ padding: "8px 14px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.09)", background: "transparent", color: m.status === "training" ? "#333" : "rgba(255,255,255,0.65)", cursor: m.status === "training" ? "default" : "pointer", minHeight: 40 }}>{t("delete_button")}</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <UseLoraModal open={!!useModalLora} onClose={() => setUseModalLora(null)} lora={useModalLora} />
    </div>
  );
}

export default function LoraTrainingPage() {
  const t = useTranslations("flows.loraTraining");
  return (
    <Suspense fallback={<div style={{ padding: 40, textAlign: "center", color: "rgba(255,255,255,0.65)" }}>{t("loading")}</div>}>
      <LoraTrainingPageInner />
    </Suspense>
  );
}

"use client";

import { Suspense, useCallback, useEffect, useRef, useState } from "react";
import { useSearchParams } from "next/navigation";
import { useTranslations } from "next-intl";
import { sanitizeUserMessage } from "@/lib/sanitize-user-message";
import {
  PRODUCT_AD_CREDITS,
  PRODUCT_AD_LOCALES,
  PRODUCT_AD_PLATFORMS,
  PRODUCT_AD_STYLES,
  PRODUCT_AD_TEMPLATES,
  type ProductAdPlatform,
  type ProductAdStyle,
} from "@/lib/product-ad-config";
import { AiOutputDisclaimer } from "@/components/ui/AiOutputDisclaimer";
import type { ProductAdScript } from "@/lib/product-ad-script";
import { LOCALE_LANGUAGE_NAMES, type Locale } from "@/lib/locale";
import { createClient } from "@/lib/supabase/client";
import { handleApiInsufficientCredits } from "@/lib/client-credits-ui";
import { ProductAdLoadingSkeleton } from "@/components/skeletons/tool-output-skeletons";

type Step = "input" | "loading" | "result";

type ScrapedProduct = {
  name: string | null;
  image: string | null;
  price: string | null;
  description: string | null;
  url: string;
};

type AdResult = {
  generationId: string;
  videoUrl: string;
  script: ProductAdScript;
  scriptText: string;
  platform: ProductAdPlatform;
  style: ProductAdStyle;
  variationFocus?: string;
  creditsUsed?: number;
  creditsLeft?: number;
  seed?: number;
};

const LOADING_STEPS = ["script", "video"] as const;

function fieldStyle(focused = false) {
  return {
    width: "100%",
    padding: "14px 16px",
    minHeight: 48,
    borderRadius: 10,
    background: "#18181d",
    border: `1px solid ${focused ? "rgba(180,255,0,0.4)" : "rgba(255,255,255,0.09)"}`,
    color: "#F0EFE8",
    fontSize: "16px",
    outline: "none",
    fontFamily: "var(--font-dm), sans-serif",
  } as const;
}

function cardStyle() {
  return {
    padding: 24,
    borderRadius: 16,
    background: "#0f0f12",
    border: "1px solid rgba(255,255,255,0.07)",
  } as const;
}

function ProduktWerbungPageInner() {
  const t = useTranslations("flows.productAd");
  const searchParams = useSearchParams();

  const [step, setStep] = useState<Step>("input");
  const [productUrl, setProductUrl] = useState("");
  const [productName, setProductName] = useState("");
  const [productDescription, setProductDescription] = useState("");
  const [productPrice, setProductPrice] = useState("");
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [audience, setAudience] = useState("");
  const [platform, setPlatform] = useState<ProductAdPlatform>("tiktok");
  const [style, setStyle] = useState<ProductAdStyle>("lifestyle");
  const [language, setLanguage] = useState<Locale>("de");
  const [ctaText, setCtaText] = useState("Jetzt kaufen");
  const [upscale, setUpscale] = useState(false);
  const [scraping, setScraping] = useState(false);
  const [scrapePreview, setScrapePreview] = useState<ScrapedProduct | null>(
    null
  );
  const [dragOver, setDragOver] = useState(false);
  const [loadingStep, setLoadingStep] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<AdResult | null>(null);
  const [batchResults, setBatchResults] = useState<AdResult[] | null>(null);
  const [editingScript, setEditingScript] = useState(false);
  const [editedScriptText, setEditedScriptText] = useState("");
  const [regenerating, setRegenerating] = useState(false);
  const [history, setHistory] = useState<
    { id: string; prompt: string; created_at: string }[]
  >([]);

  const fileRef = useRef<HTMLInputElement>(null);

  const creditSingle =
    PRODUCT_AD_CREDITS.standard +
    (upscale ? PRODUCT_AD_CREDITS.upscaleExtra : 0);
  const creditBatch =
    PRODUCT_AD_CREDITS.batch +
    (upscale ? PRODUCT_AD_CREDITS.upscaleExtra : 0);

  const loadHistory = useCallback(async () => {
    const supabase = createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) return;
    const { data } = await supabase
      .from("generations")
      .select("id, prompt, created_at")
      .eq("user_id", user.id)
      .eq("type", "product_ad")
      .order("created_at", { ascending: false })
      .limit(6);
    if (data) setHistory(data);
  }, []);

  useEffect(() => {
    loadHistory();
  }, [loadHistory]);

  useEffect(() => {
    const title = searchParams.get("title");
    const description = searchParams.get("description");
    if (title) setProductName(title);
    if (description) setProductDescription(description);
  }, [searchParams]);

  const handleFile = (file: File) => {
    if (!file.type.startsWith("image/")) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const dataUrl = e.target?.result as string;
      setImageUrl(dataUrl);
      setImagePreview(dataUrl);
      setScrapePreview(null);
    };
    reader.readAsDataURL(file);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) handleFile(file);
  };

  const handleScrape = async () => {
    if (!productUrl.trim()) return;
    setScraping(true);
    setError(null);
    try {
      const res = await fetch("/api/scrape-product", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: productUrl.trim() }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t("error_scrape"));
      const p = data.product as ScrapedProduct;
      setScrapePreview(p);
      if (p.name) setProductName(p.name);
      if (p.description) setProductDescription(p.description);
      if (p.price) setProductPrice(p.price);
      if (p.image) {
        setImageUrl(p.image);
        setImagePreview(p.image);
      }
    } catch (err) {
      setError(
        sanitizeUserMessage(err instanceof Error ? err.message : t("error_scrape"))
      );
    } finally {
      setScraping(false);
    }
  };

  const applyTemplate = (templateId: string) => {
    const tpl = PRODUCT_AD_TEMPLATES.find((x) => x.id === templateId);
    if (!tpl) return;
    setStyle(tpl.style);
    setAudience(tpl.audience);
    setCtaText(tpl.cta);
    if (!productDescription) {
      setProductDescription(tpl.tone);
    }
  };

  const canGenerate = Boolean(productName.trim() && imageUrl && audience.trim());

  const runGenerate = async (opts: { batch?: boolean; variation?: boolean; editedScript?: ProductAdScript }) => {
    if (!canGenerate || !imageUrl) return;
    setError(null);
    setStep("loading");
    setLoadingStep(0);
    setBatchResults(null);
    setResult(null);

    const payload = {
      productName: productName.trim(),
      productDescription: [productDescription, productPrice && `Price: ${productPrice}`]
        .filter(Boolean)
        .join("\n"),
      imageUrl,
      audience: audience.trim(),
      platform,
      style,
      language,
      ctaText: ctaText.trim(),
      upscale,
    };

    let scriptForVideo: ProductAdScript | undefined = opts.editedScript;

    try {
      if (!opts.batch && !scriptForVideo) {
        const scriptRes = await fetch("/api/product-ad/script", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
        const scriptData = await scriptRes.json();
        if (!scriptRes.ok || !scriptData.success) {
          throw new Error(scriptData.error || t("error_generic"));
        }
        scriptForVideo = scriptData.script as ProductAdScript;
        setLoadingStep(1);
      } else if (opts.batch) {
        setLoadingStep(1);
      }

      const res = await fetch("/api/product-ad/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...payload,
          batch: opts.batch,
          variation: opts.variation,
          editedScript: scriptForVideo,
          parentGenerationId: result?.generationId,
        }),
      });
      const data = await res.json();

      const creditCost = opts.batch ? creditBatch : creditSingle;
      if (
        handleApiInsufficientCredits(
          res.status,
          data as { error?: string; credits?: number },
          creditCost
        )
      ) {
        setStep("input");
        return;
      }

      if (!res.ok || !data.success) {
        throw new Error(data.error || t("error_generic"));
      }

      if (data.batch && Array.isArray(data.variations)) {
        setBatchResults(data.variations as AdResult[]);
      } else {
        setResult(data as AdResult);
        setEditedScriptText(data.scriptText ?? "");
      }

      setStep("result");
      loadHistory();
      window.dispatchEvent(new Event("credits-updated"));
    } catch (err) {
      setError(
        sanitizeUserMessage(err instanceof Error ? err.message : t("error_generic"))
      );
      setStep("input");
    }
  };

  const handleRegenerateWithScript = async () => {
    if (!result) return;
    setRegenerating(true);
    try {
      const parsed: ProductAdScript = {
        hook: result.script.hook,
        story: result.script.story,
        proof: result.script.proof,
        cta: result.script.cta,
        visual_style: result.script.visual_style,
      };
      if (editingScript && editedScriptText) {
        const sections = editedScriptText.split(/\n\n+/);
        sections.forEach((block) => {
          if (block.includes("[HOOK"))
            parsed.hook = block.replace(/^\[HOOK[^\]]*\]\n?/i, "").trim();
          else if (block.includes("[STORY"))
            parsed.story = block.replace(/^\[STORY[^\]]*\]\n?/i, "").trim();
          else if (block.includes("[PROOF"))
            parsed.proof = block.replace(/^\[PROOF[^\]]*\]\n?/i, "").trim();
          else if (block.includes("[CTA"))
            parsed.cta = block.replace(/^\[CTA[^\]]*\]\n?/i, "").trim();
        });
      }
      await runGenerate({ variation: true, editedScript: parsed });
      setEditingScript(false);
    } finally {
      setRegenerating(false);
    }
  };

  const downloadVideo = (generationId: string) => {
    const a = document.createElement("a");
    a.href = `/api/generated-video/${generationId}?download=1`;
    a.download = `product-ad-${generationId.slice(0, 8)}.mp4`;
    a.click();
  };

  const reset = () => {
    setStep("input");
    setResult(null);
    setBatchResults(null);
    setError(null);
  };

  const renderResultPanel = (item: AdResult, label?: string) => (
    <div
      key={item.generationId}
      style={{
        ...cardStyle(),
        display: "flex",
        flexDirection: "column",
        gap: 16,
        flex: 1,
        minWidth: 0,
      }}
    >
      {label && (
        <div
          style={{
            fontSize: "0.72rem",
            fontWeight: 800,
            letterSpacing: "0.1em",
            color: "#B4FF00",
            textTransform: "uppercase",
          }}
        >
          {label}
        </div>
      )}
      <div
        style={{
          aspectRatio: "9/16",
          maxHeight: 480,
          width: "100%",
          margin: "0 auto",
          borderRadius: 12,
          overflow: "hidden",
          background: "#060608",
        }}
      >
        <video
          src={item.videoUrl}
          controls
          playsInline
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
        />
      </div>
      <div
        style={{
          padding: 16,
          borderRadius: 12,
          background: "rgba(180,255,0,0.08)",
          border: "1px solid rgba(180,255,0,0.25)",
        }}
      >
        <div style={{ fontSize: "0.65rem", fontWeight: 800, color: "#B4FF00", marginBottom: 8, letterSpacing: "0.12em" }}>
          HOOK
        </div>
        <p style={{ margin: 0, fontSize: "1.15rem", fontWeight: 700, color: "#F0EFE8", lineHeight: 1.4 }}>
          {item.script.hook}
        </p>
      </div>
      <p style={{ margin: 0, fontSize: "0.85rem", color: "rgba(255,255,255,0.85)", lineHeight: 1.65, whiteSpace: "pre-wrap" }}>
        {item.scriptText}
      </p>
      <button
        type="button"
        onClick={() => downloadVideo(item.generationId)}
        style={{
          padding: "12px 16px",
          borderRadius: 10,
          border: "none",
          background: "#B4FF00",
          color: "#060608",
          fontWeight: 700,
          cursor: "pointer",
          minHeight: 48,
        }}
      >
        {t("download_mp4")}
      </button>
    </div>
  );

  return (
    <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 4px" }}>
      <div style={{ marginBottom: 28 }}>
        <h1
          style={{
            fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif",
            fontSize: "clamp(2rem, 4vw, 3rem)",
            letterSpacing: "0.02em",
            color: "#F0EFE8",
            marginBottom: 6,
          }}
        >
          {t("title")}
        </h1>
        <p style={{ color: "rgba(255,255,255,0.65)", fontSize: "0.9rem" }}>{t("description")}</p>
      </div>

      {error && (
        <div
          style={{
            marginBottom: 16,
            padding: "12px 16px",
            borderRadius: 10,
            background: "rgba(239,68,68,0.1)",
            border: "1px solid rgba(239,68,68,0.3)",
            color: "#fca5a5",
            fontSize: "0.88rem",
          }}
        >
          {error}
        </div>
      )}

      {step === "input" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Templates */}
          <div style={cardStyle()}>
            <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 12, letterSpacing: "0.08em", textTransform: "uppercase" }}>
              {t("templates_label")}
            </label>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
              {PRODUCT_AD_TEMPLATES.map((tpl) => (
                <button
                  key={tpl.id}
                  type="button"
                  onClick={() => applyTemplate(tpl.id)}
                  style={{
                    padding: "10px 14px",
                    borderRadius: 99,
                    border: "1px solid rgba(255,255,255,0.09)",
                    background: "#18181d",
                    color: "#F0EFE8",
                    cursor: "pointer",
                    fontSize: "0.82rem",
                    minHeight: 44,
                  }}
                >
                  {tpl.icon} {t(`template_${tpl.id}`)}
                </button>
              ))}
            </div>
          </div>

          {/* URL Scrape */}
          <div style={cardStyle()}>
            <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 10, letterSpacing: "0.08em", textTransform: "uppercase" }}>
              {t("url_label")}
            </label>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              <input
                type="url"
                value={productUrl}
                onChange={(e) => setProductUrl(e.target.value)}
                placeholder={t("url_placeholder")}
                style={fieldStyle()}
              />
              <button
                type="button"
                onClick={handleScrape}
                disabled={!productUrl.trim() || scraping}
                style={{
                  padding: "12px 16px",
                  borderRadius: 10,
                  border: "1px solid rgba(180,255,0,0.35)",
                  background: scraping ? "#18181d" : "rgba(180,255,0,0.12)",
                  color: "#B4FF00",
                  cursor: productUrl.trim() && !scraping ? "pointer" : "default",
                  minHeight: 48,
                  fontWeight: 700,
                }}
              >
                {scraping ? t("scraping") : t("scrape_button")}
              </button>
            </div>
            {scrapePreview && (
              <div style={{ marginTop: 16, padding: 14, borderRadius: 10, background: "#18181d", display: "flex", gap: 14, alignItems: "flex-start", flexWrap: "wrap" }}>
                {scrapePreview.image && (
                  <img src={scrapePreview.image} alt="" style={{ width: 72, height: 72, objectFit: "cover", borderRadius: 8 }} />
                )}
                <div style={{ flex: 1, minWidth: 160 }}>
                  <div style={{ fontWeight: 700, color: "#F0EFE8", marginBottom: 4 }}>{scrapePreview.name}</div>
                  {scrapePreview.price && <div style={{ color: "#B4FF00", fontSize: "0.85rem", marginBottom: 4 }}>{scrapePreview.price}</div>}
                  {scrapePreview.description && <div style={{ color: "rgba(255,255,255,0.65)", fontSize: "0.8rem", lineHeight: 1.5 }}>{scrapePreview.description.slice(0, 160)}ÔÇª</div>}
                </div>
              </div>
            )}
          </div>

          {/* Image upload */}
          <div style={cardStyle()}>
            <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 10, letterSpacing: "0.08em", textTransform: "uppercase" }}>
              {t("image_label")}
            </label>
            <div
              onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
              onDragLeave={() => setDragOver(false)}
              onDrop={handleDrop}
              onClick={() => fileRef.current?.click()}
              style={{
                border: `2px dashed ${dragOver ? "#B4FF00" : "rgba(255,255,255,0.12)"}`,
                borderRadius: 12,
                padding: imagePreview ? 12 : 32,
                textAlign: "center",
                cursor: "pointer",
                background: dragOver ? "rgba(180,255,0,0.05)" : "#18181d",
                minHeight: 120,
              }}
            >
              <input ref={fileRef} type="file" accept="image/*" hidden onChange={(e) => { const f = e.target.files?.[0]; if (f) handleFile(f); }} />
              {imagePreview ? (
                <img src={imagePreview} alt="" style={{ maxHeight: 200, maxWidth: "100%", borderRadius: 8, margin: "0 auto" }} />
              ) : (
                <p style={{ color: "rgba(255,255,255,0.65)", margin: 0 }}>{t("image_drop")}</p>
              )}
            </div>
          </div>

          {/* Product details */}
          <div style={{ ...cardStyle(), display: "flex", flexDirection: "column", gap: 14 }}>
            <div>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 8, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("name_label")}</label>
              <input value={productName} onChange={(e) => setProductName(e.target.value)} placeholder={t("name_placeholder")} style={fieldStyle()} />
            </div>
            <div>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 8, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("audience_label")}</label>
              <input value={audience} onChange={(e) => setAudience(e.target.value)} placeholder={t("audience_placeholder")} style={fieldStyle()} />
            </div>
            <div>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 8, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("cta_label")}</label>
              <input value={ctaText} onChange={(e) => setCtaText(e.target.value)} placeholder={t("cta_placeholder")} style={fieldStyle()} />
            </div>
          </div>

          {/* Platform */}
          <div style={cardStyle()}>
            <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 14, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("platform_label")}</label>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(140px, 1fr))", gap: 10 }}>
              {PRODUCT_AD_PLATFORMS.map((p) => (
                <button
                  key={p.id}
                  type="button"
                  onClick={() => setPlatform(p.id)}
                  style={{
                    padding: "12px 14px",
                    borderRadius: 10,
                    cursor: "pointer",
                    background: platform === p.id ? `${p.color}18` : "#18181d",
                    border: `1px solid ${platform === p.id ? p.color + "55" : "rgba(255,255,255,0.07)"}`,
                    color: platform === p.id ? "#F0EFE8" : "rgba(255,255,255,0.65)",
                    minHeight: 48,
                    textAlign: "left",
                    fontWeight: 700,
                    fontSize: "0.85rem",
                  }}
                >
                  {t(`platform_${p.id}`)}
                </button>
              ))}
            </div>
          </div>

          {/* Style + Language */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 16 }}>
            <div style={cardStyle()}>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 10, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("style_label")}</label>
              <select value={style} onChange={(e) => setStyle(e.target.value as ProductAdStyle)} style={{ ...fieldStyle(), cursor: "pointer" }}>
                {PRODUCT_AD_STYLES.map((s) => (
                  <option key={s} value={s}>{t(`style_${s}`)}</option>
                ))}
              </select>
            </div>
            <div style={cardStyle()}>
              <label style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", display: "block", marginBottom: 10, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("language_label")}</label>
              <select value={language} onChange={(e) => setLanguage(e.target.value as Locale)} style={{ ...fieldStyle(), cursor: "pointer" }}>
                {PRODUCT_AD_LOCALES.map((loc) => (
                  <option key={loc} value={loc}>{LOCALE_LANGUAGE_NAMES[loc]}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Upscale */}
          <label style={{ display: "flex", alignItems: "center", gap: 12, padding: "14px 18px", borderRadius: 12, background: "#0f0f12", border: "1px solid rgba(255,255,255,0.07)", cursor: "pointer", minHeight: 48 }}>
            <input type="checkbox" checked={upscale} onChange={(e) => setUpscale(e.target.checked)} style={{ width: 20, height: 20, accentColor: "#B4FF00" }} />
            <span style={{ color: "#F0EFE8", fontSize: "0.9rem" }}>{t("upscale_label", { credits: PRODUCT_AD_CREDITS.upscaleExtra })}</span>
          </label>

          {/* Actions */}
          <button
            type="button"
            onClick={() => runGenerate({ batch: false })}
            disabled={!canGenerate}
            style={{
              width: "100%",
              padding: "15px",
              borderRadius: 12,
              border: "none",
              background: canGenerate ? "#B4FF00" : "#2a2a2a",
              color: canGenerate ? "#060608" : "rgba(255,255,255,0.65)",
              fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif",
              fontSize: "1.3rem",
              letterSpacing: "0.04em",
              cursor: canGenerate ? "pointer" : "default",
              minHeight: 52,
            }}
          >
            {t("generate_button", { credits: creditSingle })}
          </button>
          <button
            type="button"
            onClick={() => runGenerate({ batch: true })}
            disabled={!canGenerate}
            style={{
              width: "100%",
              padding: "14px",
              borderRadius: 12,
              border: "1px solid rgba(180,255,0,0.35)",
              background: "transparent",
              color: canGenerate ? "#B4FF00" : "rgba(255,255,255,0.65)",
              fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif",
              fontSize: "1.1rem",
              letterSpacing: "0.04em",
              cursor: canGenerate ? "pointer" : "default",
              minHeight: 52,
            }}
          >
            {t("batch_button", { credits: creditBatch })}
          </button>

          {history.length > 0 && (
            <div style={cardStyle()}>
              <div style={{ fontSize: "0.78rem", fontWeight: 700, color: "rgba(255,255,255,0.65)", marginBottom: 12, letterSpacing: "0.08em", textTransform: "uppercase" }}>{t("history_title")}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {history.map((h) => (
                  <div key={h.id} style={{ fontSize: "0.82rem", color: "rgba(240,239,232,0.7)", display: "flex", justifyContent: "space-between", gap: 8 }}>
                    <span>{h.prompt || "Product Ad"}</span>
                    <span style={{ color: "rgba(255,255,255,0.65)", flexShrink: 0 }}>{new Date(h.created_at).toLocaleDateString()}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {step === "loading" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <p
            style={{
              textAlign: "center",
              fontFamily: "var(--font-bebas), 'Bebas Neue', sans-serif",
              fontSize: "1.2rem",
              color: "#B4FF00",
              letterSpacing: "0.04em",
            }}
          >
            {t(`loading_${LOADING_STEPS[loadingStep]}`)}
          </p>
          <ProductAdLoadingSkeleton />
          <p style={{ textAlign: "center", color: "rgba(255,255,255,0.55)", fontSize: "0.82rem" }}>
            {t("loading_hint")}
          </p>
        </div>
      )}

      {step === "result" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <button type="button" onClick={reset} style={{ alignSelf: "flex-start", padding: "8px 16px", borderRadius: 8, background: "transparent", border: "1px solid rgba(255,255,255,0.09)", color: "rgba(255,255,255,0.65)", cursor: "pointer", minHeight: 44 }}>
            ÔåÉ {t("back_button")}
          </button>

          {batchResults ? (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))", gap: 16 }}>
              {batchResults.map((item, i) =>
                renderResultPanel(
                  item,
                  [t("variation_hook"), t("variation_lifestyle"), t("variation_problem")][i]
                )
              )}
            </div>
          ) : result ? (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 20, alignItems: "start" }}>
              <div style={{ width: "100%" }}>
                <div style={{ aspectRatio: "9/16", maxWidth: 360, margin: "0 auto", borderRadius: 16, overflow: "hidden", background: "#060608" }}>
                  <video src={result.videoUrl} controls playsInline style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                </div>
                <p style={{ textAlign: "center", fontSize: "0.75rem", color: "rgba(255,255,255,0.65)", marginTop: 10 }}>{t("mobile_download_hint")}</p>
                <div style={{ display: "flex", flexDirection: "column", gap: 10, marginTop: 14, maxWidth: 360, margin: "14px auto 0" }}>
                  <button type="button" onClick={() => downloadVideo(result.generationId)} style={{ padding: "12px", borderRadius: 10, border: "none", background: "#B4FF00", color: "#060608", fontWeight: 700, cursor: "pointer", minHeight: 48 }}>
                    {t("download_mp4")}
                  </button>
                  <button type="button" onClick={() => runGenerate({ variation: true })} disabled={regenerating} style={{ padding: "12px", borderRadius: 10, border: "1px solid rgba(180,255,0,0.35)", background: "transparent", color: "#B4FF00", fontWeight: 700, cursor: "pointer", minHeight: 48 }}>
                    {t("variation_button")}
                  </button>
                </div>
              </div>
              <div style={{ ...cardStyle(), display: "flex", flexDirection: "column", gap: 14 }}>
                <div style={{ padding: 16, borderRadius: 12, background: "rgba(180,255,0,0.08)", border: "1px solid rgba(180,255,0,0.25)" }}>
                  <div style={{ fontSize: "0.65rem", fontWeight: 800, color: "#B4FF00", marginBottom: 8, letterSpacing: "0.12em" }}>HOOK</div>
                  <p style={{ margin: 0, fontSize: "clamp(1.1rem, 3vw, 1.45rem)", fontWeight: 700, color: "#F0EFE8", lineHeight: 1.35 }}>{result.script.hook}</p>
                </div>
                {editingScript ? (
                  <textarea
                    value={editedScriptText}
                    onChange={(e) => setEditedScriptText(e.target.value)}
                    rows={12}
                    style={{ ...fieldStyle(), resize: "vertical", lineHeight: 1.65, fontSize: "0.9rem" }}
                  />
                ) : (
                  <p style={{ margin: 0, fontSize: "0.9rem", color: "rgba(240,239,232,0.8)", lineHeight: 1.75, whiteSpace: "pre-wrap" }}>{result.scriptText}</p>
                )}
                <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
                  <button type="button" onClick={() => setEditingScript(!editingScript)} style={{ padding: "10px 14px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.09)", background: "#18181d", color: "#F0EFE8", cursor: "pointer", minHeight: 44 }}>
                    {editingScript ? t("script_cancel") : t("script_edit")}
                  </button>
                  {editingScript && (
                    <button type="button" onClick={handleRegenerateWithScript} disabled={regenerating} style={{ padding: "10px 14px", borderRadius: 8, border: "none", background: "#B4FF00", color: "#060608", fontWeight: 700, cursor: "pointer", minHeight: 44 }}>
                      {t("script_apply")}
                    </button>
                  )}
                </div>
              </div>
            </div>
          ) : null}
          {(batchResults || result) && <AiOutputDisclaimer />}
        </div>
      )}
    </div>
  );
}

export default function ProduktWerbungPage() {
  const t = useTranslations("flows.productAd");
  return (
    <Suspense fallback={<div style={{ padding: 40, textAlign: "center", color: "rgba(255,255,255,0.65)" }}>{t("loading_page")}</div>}>
      <ProduktWerbungPageInner />
    </Suspense>
  );
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { flushSync } from "react-dom";
import { useTranslations } from "next-intl";
import { fal } from "@fal-ai/client";
import {
  FAL_FLASHHEAD_MODEL,
  LIVE_CREATOR_CREDITS_PER_MINUTE,
  LIVE_CREATOR_FALLBACK_INTERVAL_MS,
  LIVE_CREATOR_FRAME_INTERVAL_MS,
  LIVE_CREATOR_HEARTBEAT_MS,
  LIVE_CREATOR_LOW_CREDITS_WARNING,
  PREFERRED_LIVE_CHARACTER_KEY,
  type LiveCreatorCharacter,
} from "@/lib/live-creator-config";
import {
  captureVideoFrame,
  extractRealtimeFrameUrl,
  loadImageAsDataUrl,
  readFileAsDataUrl,
  type FlashheadRealtimeResult,
} from "@/lib/live-creator-webcam";
import { createClient } from "@/lib/supabase/client";
import { sanitizeUserMessage } from "@/lib/sanitize-user-message";
import { AiOutputDisclaimer } from "@/components/ui/AiOutputDisclaimer";

async function uploadCustomAvatar(file: File): Promise<string> {
  const supabase = createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Nicht eingeloggt");

  const ext = file.name.split(".").pop() ?? "jpg";
  const path = `${user.id}/live-creator/${Date.now()}.${ext}`;

  const { error } = await supabase.storage
    .from("avatar-assets")
    .upload(path, file, {
      contentType: file.type,
      upsert: true,
    });

  if (error) throw new Error(error.message);

  const { data } = supabase.storage.from("avatar-assets").getPublicUrl(path);
  return data.publicUrl;
}

type StudioPhase = "setup" | "connecting" | "live" | "ended";
type StreamMode = "realtime" | "fallback";

type FlashheadSendPayload = {
  source_image: string;
  driving_frame: string;
  image_url: string;
};

export function LiveCreatorStudioInner() {
  const t = useTranslations("liveCreatorStudio");

  const [phase, setPhase] = useState<StudioPhase>("setup");
  const [characters, setCharacters] = useState<LiveCreatorCharacter[]>([]);
  const [selectedCharacterId, setSelectedCharacterId] = useState("");
  const [credits, setCredits] = useState<number | null>(null);
  const [creditsUsed, setCreditsUsed] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [lowCredits, setLowCredits] = useState(false);
  const [streamMode, setStreamMode] = useState<StreamMode>("realtime");
  const [outputUrl, setOutputUrl] = useState<string | null>(null);
  const [uploadPreview, setUploadPreview] = useState<string | null>(null);
  const [customAvatarFile, setCustomAvatarFile] = useState<File | null>(null);
  const [consentAccepted, setConsentAccepted] = useState(false);

  const outputVideoRef = useRef<HTMLVideoElement>(null);
  const outputImageRef = useRef<HTMLImageElement>(null);
  const webcamVideoRef = useRef<HTMLVideoElement>(null);
  const webcamStreamRef = useRef<MediaStream | null>(null);
  const characterDataUrlRef = useRef<string>("");
  const connectionRef = useRef<ReturnType<typeof fal.realtime.connect> | null>(
    null
  );
  const frameLoopRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const fallbackLoopRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const heartbeatRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const recorderRef = useRef<MediaRecorder | null>(null);
  const recorderChunksRef = useRef<Blob[]>([]);
  const fallbackBusyRef = useRef(false);
  const uploadInputRef = useRef<HTMLInputElement>(null);

  const stopFrameLoops = () => {
    if (frameLoopRef.current) {
      clearInterval(frameLoopRef.current);
      frameLoopRef.current = null;
    }
    if (fallbackLoopRef.current) {
      clearInterval(fallbackLoopRef.current);
      fallbackLoopRef.current = null;
    }
  };

  const stopHeartbeat = () => {
    if (heartbeatRef.current) {
      clearInterval(heartbeatRef.current);
      heartbeatRef.current = null;
    }
  };

  const stopWebcam = () => {
    stopFrameLoops();
    recorderRef.current?.stop();
    recorderRef.current = null;
    recorderChunksRef.current = [];

    webcamStreamRef.current?.getTracks().forEach((track) => track.stop());
    webcamStreamRef.current = null;

    if (webcamVideoRef.current) {
      webcamVideoRef.current.srcObject = null;
    }
  };

  const closeRealtime = () => {
    connectionRef.current?.close();
    connectionRef.current = null;
  };

  const cleanupSession = useCallback(async () => {
    stopHeartbeat();
    stopWebcam();
    closeRealtime();
  }, []);

  const displayFrame = useCallback((url: string, isVideo = false) => {
    setOutputUrl(url);
    if (isVideo && outputVideoRef.current) {
      outputVideoRef.current.src = url;
      void outputVideoRef.current.play().catch(() => {});
      return;
    }
    if (outputImageRef.current) {
      outputImageRef.current.src = url;
    }
  }, []);

  const runHeartbeat = async () => {
    const res = await fetch("/api/live-creator/studio/heartbeat", {
      method: "POST",
    });
    const data = await res.json();
    if (typeof data.creditsLeft === "number") {
      setCredits(data.creditsLeft);
      window.dispatchEvent(new Event("credits-updated"));
    }
    if (typeof data.creditsUsed === "number" && data.creditsUsed > 0) {
      setCreditsUsed((prev) => prev + data.creditsUsed);
    }
    if (data.lowCredits) setLowCredits(true);
    if (data.endSession || !data.success) {
      setError(sanitizeUserMessage(data.error ?? t("no_credits_end")));
      await endSession();
    }
  };

  const startHeartbeat = () => {
    stopHeartbeat();
    heartbeatRef.current = setInterval(() => {
      void runHeartbeat();
    }, LIVE_CREATOR_HEARTBEAT_MS);
    void runHeartbeat();
  };

  const loadStudio = useCallback(async () => {
    setError(null);
    try {
      const res = await fetch("/api/live-creator/studio");
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t("error_load"));

      const list: LiveCreatorCharacter[] = data.characters ?? [];
      setCharacters(list);
      setCredits(data.credits ?? 0);

      const stored =
        typeof window !== "undefined"
          ? localStorage.getItem(PREFERRED_LIVE_CHARACTER_KEY)
          : null;
      const preferred =
        (stored && list.some((c) => c.id === stored)
          ? stored
          : data.preferredCharacterId) ||
        list[0]?.id ||
        "";

      if (preferred) setSelectedCharacterId(preferred);

      if ((data.credits ?? 0) < LIVE_CREATOR_LOW_CREDITS_WARNING) {
        setLowCredits(true);
      }
    } catch (err) {
      setError(
        sanitizeUserMessage(
          err instanceof Error ? err.message : t("error_load")
        )
      );
    }
  }, [t]);

  useEffect(() => {
    void loadStudio();
  }, [loadStudio]);

  useEffect(() => {
    return () => {
      void cleanupSession();
    };
  }, [cleanupSession]);

  const resolveCharacter = (): LiveCreatorCharacter | undefined => {
    if (uploadPreview && selectedCharacterId === "upload") {
      return {
        id: "upload",
        name: t("upload_character"),
        imageUrl: uploadPreview,
        kind: "upload",
      };
    }
    return characters.find((c) => c.id === selectedCharacterId);
  };

  const pickCharacter = (id: string) => {
    setSelectedCharacterId(id);
    localStorage.setItem(PREFERRED_LIVE_CHARACTER_KEY, id);
  };

  const handleUpload = async (file: File) => {
    if (!file.type.startsWith("image/")) return;
    const dataUrl = await readFileAsDataUrl(file);
    setUploadPreview(dataUrl);
    setCustomAvatarFile(file);
    setSelectedCharacterId("upload");
    localStorage.setItem(PREFERRED_LIVE_CHARACTER_KEY, "upload");
  };

  const startWebcam = async () => {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: {
        width: { ideal: 640 },
        height: { ideal: 640 },
        facingMode: "user",
      },
      audio: false,
    });

    webcamStreamRef.current = stream;
    if (webcamVideoRef.current) {
      webcamVideoRef.current.srcObject = stream;
      await webcamVideoRef.current.play();
    }

    if (typeof MediaRecorder !== "undefined") {
      try {
        const recorder = new MediaRecorder(stream, {
          mimeType: MediaRecorder.isTypeSupported("video/webm;codecs=vp8")
            ? "video/webm;codecs=vp8"
            : "video/webm",
        });
        recorder.ondataavailable = (event) => {
          if (event.data.size > 0) {
            recorderChunksRef.current.push(event.data);
            if (recorderChunksRef.current.length > 4) {
              recorderChunksRef.current.shift();
            }
          }
        };
        recorder.start(500);
        recorderRef.current = recorder;
      } catch {
        /* fallback uses JPEG frames */
      }
    }
  };

  const getDrivingVideoDataUrl = async (): Promise<string | undefined> => {
    const chunks = recorderChunksRef.current;
    if (!chunks.length) return undefined;
    const blob = new Blob(chunks, { type: "video/webm" });
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = () => resolve(undefined);
      reader.readAsDataURL(blob);
    });
  };

  const sendRealtimeFrame = () => {
    const video = webcamVideoRef.current;
    const connection = connectionRef.current;
    if (!video || !connection || !characterDataUrlRef.current) return;

    const drivingFrame = captureVideoFrame(video);
    if (!drivingFrame) return;

    connection.send({
      source_image: characterDataUrlRef.current,
      driving_frame: drivingFrame,
      image_url: characterDataUrlRef.current,
    } as FlashheadSendPayload & { request_id?: string });
  };

  const pollFallbackFrame = async () => {
    if (fallbackBusyRef.current) return;
    const video = webcamVideoRef.current;
    if (!video || !characterDataUrlRef.current) return;

    const drivingFrame = captureVideoFrame(video);
    if (!drivingFrame) return;

    fallbackBusyRef.current = true;
    try {
      const drivingVideoDataUrl = await getDrivingVideoDataUrl();
      const res = await fetch("/api/live-creator/portrait-frame", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          sourceImage: characterDataUrlRef.current,
          drivingFrame,
          drivingVideoDataUrl,
          consentAccepted: true,
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t("error_session"));

      if (typeof data.imageUrl === "string") {
        const isVideo = /\.(mp4|webm)(\?|$)/i.test(data.imageUrl);
        displayFrame(data.imageUrl, isVideo);
      }
    } catch (err) {
      console.error("[live-creator fallback]", err);
    } finally {
      fallbackBusyRef.current = false;
    }
  };

  const activateFallback = () => {
    if (streamMode === "fallback") return;
    setStreamMode("fallback");
    closeRealtime();
    stopFrameLoops();
    fallbackLoopRef.current = setInterval(() => {
      void pollFallbackFrame();
    }, LIVE_CREATOR_FALLBACK_INTERVAL_MS);
    void pollFallbackFrame();
  };

  const connectRealtime = () => {
    const connection = fal.realtime.connect(FAL_FLASHHEAD_MODEL, {
      clientOnly: true,
      throttleInterval: LIVE_CREATOR_FRAME_INTERVAL_MS,
      maxBuffering: 2,
      tokenProvider: async (app) => {
        const res = await fetch("/api/fal/realtime-token", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ app, consentAccepted: true }),
        });
        if (!res.ok) {
          throw new Error("Realtime-Token fehlgeschlagen");
        }
        return res.text();
      },
      tokenExpirationSeconds: 100,
      onResult: (result: FlashheadRealtimeResult) => {
        const url = extractRealtimeFrameUrl(result);
        if (!url) return;
        const isVideo = /\.(mp4|webm)(\?|$)/i.test(url);
        displayFrame(url, isVideo);
      },
      onError: () => {
        activateFallback();
      },
    });

    connectionRef.current = connection;
    setStreamMode("realtime");

    frameLoopRef.current = setInterval(() => {
      sendRealtimeFrame();
    }, LIVE_CREATOR_FRAME_INTERVAL_MS);
  };

  const startSession = async () => {
    const character = resolveCharacter();
    if (!character) return;

    setError(null);
    flushSync(() => {
      setPhase("connecting");
    });
    setCreditsUsed(0);
    setStreamMode("realtime");
    setOutputUrl(null);

    try {
      const startRes = await fetch("/api/live-creator/studio", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ consentAccepted: true }),
      });
      const startData = await startRes.json();
      if (!startRes.ok) {
        throw new Error(startData.error || t("error_session"));
      }
      if (typeof startData.credits === "number") {
        setCredits(startData.credits);
      }

      let sourceImageUrl = character.imageUrl;
      if (selectedCharacterId === "upload" && customAvatarFile) {
        try {
          sourceImageUrl = await uploadCustomAvatar(customAvatarFile);
        } catch {
          throw new Error("Bild-Upload fehlgeschlagen. Erneut versuchen.");
        }
      }

      characterDataUrlRef.current = await loadImageAsDataUrl(sourceImageUrl);
      await startWebcam();

      try {
        connectRealtime();
      } catch {
        activateFallback();
      }

      setPhase("live");
      startHeartbeat();
    } catch (err) {
      await cleanupSession();
      setPhase("setup");
      setError(
        sanitizeUserMessage(
          err instanceof Error ? err.message : t("error_session")
        )
      );
    }
  };

  const endSession = async () => {
    setPhase("ended");
    await cleanupSession();
    setPhase("setup");
    setStreamMode("realtime");
    setOutputUrl(null);
  };

  const canStart =
    consentAccepted &&
    (selectedCharacterId === "upload" ? !!uploadPreview : !!selectedCharacterId) &&
    (credits === null || credits >= LIVE_CREATOR_CREDITS_PER_MINUTE);

  const selectedCharacter = resolveCharacter();

  return (
    <div className="mx-auto w-full max-w-2xl pb-24">
      {(lowCredits ||
        (credits !== null && credits < LIVE_CREATOR_LOW_CREDITS_WARNING)) && (
        <div className="mb-4 rounded-xl border border-amber-500/30 bg-amber-500/10 px-4 py-3 text-sm text-amber-200">
          {t("low_credits", { count: credits ?? 0 })}
        </div>
      )}

      {error && (
        <div className="mb-4 rounded-xl border border-red-400/30 bg-red-500/10 px-4 py-3 text-sm text-red-300">
          {error}
        </div>
      )}

      {streamMode === "fallback" && phase === "live" && (
        <div className="mb-3 rounded-lg border border-amber-500/25 bg-amber-500/5 px-3 py-2 text-xs text-amber-200/90">
          {t("fallback_mode")}
        </div>
      )}

      <div
        className="relative mx-auto overflow-hidden rounded-2xl border border-[#B4FF00]/20 bg-[#060608]"
        style={{ height: "min(78vh, 720px)" }}
      >
        {phase === "live" && (
          <span className="absolute top-3 left-3 z-30 flex items-center gap-2 rounded-full bg-red-600/90 px-3 py-1 text-xs font-bold uppercase tracking-wider text-white animate-pulse">
            <span className="h-2 w-2 rounded-full bg-white" />
            {t("live_badge")}
          </span>
        )}

        <div
          className="relative w-full bg-[#060608]"
          style={{ height: "65%" }}
        >
          {outputUrl ? (
            /\.(mp4|webm)(\?|$)/i.test(outputUrl) ? (
              <video
                ref={outputVideoRef}
                src={outputUrl}
                className="absolute inset-0 h-full w-full object-cover"
                autoPlay
                muted
                playsInline
                loop
              />
            ) : (
              // eslint-disable-next-line @next/next/no-img-element
              <img
                ref={outputImageRef}
                src={outputUrl}
                alt=""
                className="absolute inset-0 h-full w-full object-cover"
              />
            )
          ) : (
            selectedCharacter ? (
              // eslint-disable-next-line @next/next/no-img-element
              <img
                src={selectedCharacter.imageUrl}
                alt=""
                className="absolute inset-0 h-full w-full object-cover opacity-40"
              />
            ) : (
              <div className="absolute inset-0 flex items-center justify-center text-white/25 text-sm">
                {t("output_placeholder")}
              </div>
            )
          )}

          {(phase === "connecting" || phase === "live") && (
            <video
              ref={webcamVideoRef}
              className={
                phase === "live"
                  ? "absolute bottom-3 right-3 z-30 h-[200px] w-[200px] rounded-full border-2 border-[#B4FF00]/50 object-cover shadow-lg shadow-black/60 bg-black scale-x-[-1]"
                  : "pointer-events-none absolute -left-[9999px] h-px w-px opacity-0"
              }
              muted
              playsInline
            />
          )}
        </div>

        <div
          className="relative flex flex-col border-t border-white/10 bg-[#060608]/95"
          style={{ height: "35%" }}
        >
          {phase === "setup" && (
            <div className="flex h-full flex-col overflow-y-auto p-4">
              <p className="text-white/80 text-sm mb-3">{t("pick_character")}</p>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 flex-1 min-h-0 overflow-y-auto mb-3">
                {characters.map((c) => {
                  const selected = selectedCharacterId === c.id;
                  return (
                    <button
                      key={c.id}
                      type="button"
                      onClick={() => pickCharacter(c.id)}
                      className={`relative aspect-[3/4] rounded-xl overflow-hidden border-2 transition-all ${
                        selected
                          ? "border-[#B4FF00] ring-2 ring-[#B4FF00]/30"
                          : "border-white/10 hover:border-white/25"
                      }`}
                    >
                      {/* eslint-disable-next-line @next/next/no-img-element */}
                      <img
                        src={c.imageUrl}
                        alt={c.name}
                        className="absolute inset-0 h-full w-full object-cover"
                      />
                      <span className="absolute bottom-0 inset-x-0 bg-black/70 px-1.5 py-1 text-[0.6rem] font-medium text-white truncate">
                        {c.name}
                      </span>
                    </button>
                  );
                })}
                <button
                  type="button"
                  onClick={() => {
                    setSelectedCharacterId("upload");
                    uploadInputRef.current?.click();
                  }}
                  className={`relative aspect-[3/4] rounded-xl overflow-hidden border-2 border-dashed transition-all ${
                    selectedCharacterId === "upload"
                      ? "border-[#B4FF00] bg-[#B4FF00]/5"
                      : "border-white/15 hover:border-white/30"
                  }`}
                >
                  {uploadPreview ? (
                    // eslint-disable-next-line @next/next/no-img-element
                    <img
                      src={uploadPreview}
                      alt=""
                      className="absolute inset-0 h-full w-full object-cover"
                    />
                  ) : (
                    <div className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-white/75 text-[0.65rem] px-2 text-center">
                      <span className="text-xl">+</span>
                      {t("upload_character")}
                    </div>
                  )}
                </button>
              </div>
              <input
                ref={uploadInputRef}
                type="file"
                accept="image/*"
                className="hidden"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) void handleUpload(file);
                }}
              />
              <label className="flex items-start gap-3 rounded-xl border border-white/10 bg-white/5 p-3 mb-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={consentAccepted}
                  onChange={(e) => setConsentAccepted(e.target.checked)}
                  className="mt-0.5 h-4 w-4 shrink-0 accent-[#B4FF00]"
                />
                <span className="text-xs text-white/75 leading-relaxed">
                  Ich habe die Rechte und Einwilligung f├╝r das gew├ñhlte Bild und
                  meine Webcam-Aufnahme. Ich verwende keine Inhalte anderer
                  Personen ohne deren Zustimmung. Ich verstehe, dass daraus
                  KI-animierte Inhalte entstehen k├Ânnen.
                </span>
              </label>
              <button
                type="button"
                disabled={!canStart}
                onClick={() => void startSession()}
                className="w-full shrink-0 rounded-xl bg-[#B4FF00] py-3 text-sm font-semibold text-[#060608] disabled:opacity-40"
              >
                {t("start_session")}
              </button>
              <p className="text-white/65 text-xs text-center mt-2">
                {t("credits_hint", { cost: LIVE_CREATOR_CREDITS_PER_MINUTE })}
              </p>
            </div>
          )}

          {phase === "connecting" && (
            <div className="flex flex-1 items-center justify-center">
              <p className="text-[#B4FF00] text-sm font-medium animate-pulse">
                {t("connecting")}
              </p>
            </div>
          )}

          {phase === "live" && (
            <div className="flex flex-1 flex-col justify-between p-4">
              <div className="flex items-center justify-between gap-3 text-xs text-white/80">
                <span>{selectedCharacter?.name}</span>
                <span>
                  {t("credits_used", { count: creditsUsed })}
                  {credits !== null ? ` ┬À ${credits} ${t("credits_left")}` : ""}
                </span>
              </div>
              <div className="flex items-center justify-center gap-3">
                <button
                  type="button"
                  onClick={() => void endSession()}
                  className="rounded-xl bg-red-600 px-6 py-2.5 text-sm font-semibold text-white"
                >
                  {t("stop_session")}
                </button>
              </div>
              <p className="text-center text-white/65 text-[0.65rem]">
                {t("billing_active", {
                  credits: credits ?? 0,
                  cost: LIVE_CREATOR_CREDITS_PER_MINUTE,
                })}
              </p>
            </div>
          )}
        </div>
      </div>
      {outputUrl ? <AiOutputDisclaimer className="mt-3 px-1" /> : null}
    </div>
  );
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { usePathname } from "next/navigation";
import { ArrowUp, X } from "lucide-react";
import { handleApiPlanRequired, openBuyCreditsModal } from "@/lib/client-credits-ui";
import { formatStarterFromPrice } from "@/lib/pricing";

type ChatMessage = {
  id: string;
  role: "user" | "assistant";
  content: string;
};

type Props = {
  userName?: string | null;
  currentPath?: string;
};

function displayFirstName(fullName?: string | null): string {
  const trimmed = fullName?.trim();
  if (!trimmed) return "du";
  return trimmed.split(/\s+/)[0] ?? "du";
}

function welcomeMessage(name: string): string {
  return `Hallo ${name} ­ƒæï Ich bin Melodia, deine pers├Ânliche Assistentin. Womit kann ich dir heute helfen?`;
}

export default function MelodiaWidget({ userName, currentPath }: Props) {
  const pathname = usePathname();
  const resolvedPath = currentPath ?? pathname ?? "/dashboard";

  const [open, setOpen] = useState(false);
  const [input, setInput] = useState("");
  const [running, setRunning] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>(() => [
    {
      id: "welcome",
      role: "assistant",
      content: welcomeMessage(displayFirstName(userName)),
    },
  ]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (open) {
      inputRef.current?.focus();
    }
  }, [open]);

  useEffect(() => {
    scrollRef.current?.scrollTo({
      top: scrollRef.current.scrollHeight,
      behavior: "smooth",
    });
  }, [messages, running, open]);

  const sendMessage = useCallback(
    async (text: string) => {
      const msg = text.trim();
      if (!msg || running) return;

      setInput("");
      setRunning(true);

      const userMsg: ChatMessage = {
        id: `u-${Date.now()}`,
        role: "user",
        content: msg,
      };
      const assistantId = `a-${Date.now()}`;
      const assistantMsg: ChatMessage = {
        id: assistantId,
        role: "assistant",
        content: "",
      };

      setMessages((prev) => [...prev, userMsg, assistantMsg]);

      const history = [...messages, userMsg]
        .filter((m) => m.id !== "welcome" || m.role === "user")
        .filter((m) => m.content.trim())
        .map((m) => ({ role: m.role, content: m.content }));

      try {
        const res = await fetch("/api/melodia", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            message: msg,
            history: history.slice(0, -1),
            currentPath: resolvedPath,
            userName,
          }),
        });

        if (res.status === 403) {
          handleApiPlanRequired();
          setMessages((prev) =>
            prev.map((m) =>
              m.id === assistantId
                ? {
                    ...m,
                    content:
                      `W├ñhle einen Plan um zu starten ÔÇö alle Tools ab Ôé¼${formatStarterFromPrice("de")}/Monat inklusive.`,
                  }
                : m
            )
          );
          return;
        }

        if (res.status === 402) {
          openBuyCreditsModal();
          setMessages((prev) =>
            prev.map((m) =>
              m.id === assistantId
                ? {
                    ...m,
                    content:
                      "Du hast leider keine Credits mehr. Lade unter ÔÇ×Credits & PlanÔÇ£ auf ÔÇö dann bin ich sofort wieder f├╝r dich da.",
                  }
                : m
            )
          );
          return;
        }

        if (!res.ok || !res.body) {
          setMessages((prev) =>
            prev.map((m) =>
              m.id === assistantId
                ? {
                    ...m,
                    content: "Entschuldigung, das hat gerade nicht geklappt. Versuch es bitte noch einmal.",
                  }
                : m
            )
          );
          return;
        }

        const reader = res.body.getReader();
        const decoder = new TextDecoder();
        let buffer = "";

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          buffer += decoder.decode(value, { stream: true });

          const parts = buffer.split("\n\n");
          buffer = parts.pop() ?? "";

          for (const part of parts) {
            const line = part.trim();
            if (!line.startsWith("data: ")) continue;
            let event: { type?: string; text?: string; message?: string };
            try {
              event = JSON.parse(line.slice(6));
            } catch {
              continue;
            }

            if (event.type === "text_delta" && event.text) {
              setMessages((prev) =>
                prev.map((m) =>
                  m.id === assistantId
                    ? { ...m, content: m.content + event.text }
                    : m
                )
              );
            } else if (event.type === "error" && event.message) {
              setMessages((prev) =>
                prev.map((m) =>
                  m.id === assistantId
                    ? { ...m, content: event.message! }
                    : m
                )
              );
            } else if (event.type === "credits") {
              window.dispatchEvent(new Event("credits-updated"));
            }
          }
        }
      } catch {
        setMessages((prev) =>
          prev.map((m) =>
            m.id === assistantId
              ? {
                  ...m,
                  content: "Netzwerkfehler ÔÇö bitte pr├╝fe deine Verbindung und versuche es erneut.",
                }
              : m
          )
        );
      } finally {
        setRunning(false);
      }
    },
    [messages, running, resolvedPath, userName]
  );

  const orb = (size: "lg" | "sm") => {
    const dim = size === "lg" ? 48 : 32;
    const fontSize = size === "lg" ? 18 : 13;
    const lgClass =
      size === "lg"
        ? "inline-grid place-items-center rounded-full bg-[var(--accent,#B4FF00)] text-[#060608] font-extrabold melodia-orb-pulse h-12 w-12 text-lg md:h-14 md:w-14 md:text-xl"
        : "inline-grid shrink-0 place-items-center rounded-full bg-[var(--accent,#B4FF00)] text-[#060608] font-extrabold h-8 w-8 text-[13px]";
    return (
      <span
        className={lgClass}
        style={
          size === "lg"
            ? {
                boxShadow:
                  "0 0 20px color-mix(in srgb, var(--accent, #B4FF00) 60%, transparent)",
              }
            : undefined
        }
        aria-hidden
      >
        M
      </span>
    );
  };

  return (
    <>
      <style jsx global>{`
        @keyframes melodia-orb-pulse {
          0%,
          100% {
            transform: scale(1);
          }
          50% {
            transform: scale(1.05);
          }
        }
        .melodia-orb-pulse {
          animation: melodia-orb-pulse 2s ease-in-out infinite;
        }
      `}</style>

      <div
        className="melodia-widget-root pointer-events-none fixed z-40 flex flex-col items-end gap-3 max-md:bottom-[calc(88px+env(safe-area-inset-bottom,0px)+12px)] max-md:right-4 md:bottom-6 md:right-6"
      >
        {open && (
          <div
            className="pointer-events-auto flex w-[360px] max-w-[calc(100vw-2rem)] flex-col overflow-hidden rounded-[20px] border border-white/10 bg-[#0f0f12] shadow-[0_20px_60px_rgba(0,0,0,0.6)] max-md:max-h-[min(520px,calc(100dvh-160px-env(safe-area-inset-top,0px)-env(safe-area-inset-bottom,0px)))]"
            style={{ height: 520 }}
            role="dialog"
            aria-label="Melodia Chat"
          >
            <header className="flex shrink-0 items-center justify-between border-b border-white/[0.08] px-4 py-3">
              <div className="flex min-w-0 items-center gap-2.5">
                {orb("sm")}
                <div className="min-w-0">
                  <p className="text-sm font-semibold text-[#F0EFE8] leading-none">
                    Melodia
                  </p>
                  <p className="mt-1 flex items-center gap-1.5 text-[11px] text-white/50">
                    <span
                      className="inline-block h-1.5 w-1.5 rounded-full bg-[var(--accent,#B4FF00)]"
                      aria-hidden
                    />
                    Online
                  </p>
                </div>
              </div>
              <button
                type="button"
                onClick={() => setOpen(false)}
                className="flex h-8 w-8 items-center justify-center rounded-lg text-white/50 hover:bg-white/5 hover:text-white/80 transition-colors"
                aria-label="Schlie├ƒen"
              >
                <X size={18} />
              </button>
            </header>

            <div
              ref={scrollRef}
              className="flex-1 space-y-3 overflow-y-auto px-4 py-4"
            >
              {messages.map((m) => (
                <div
                  key={m.id}
                  className={`flex ${m.role === "user" ? "justify-end" : "justify-start"}`}
                >
                  <div
                    className={`max-w-[85%] rounded-2xl px-3.5 py-2.5 text-sm leading-relaxed whitespace-pre-wrap ${
                      m.role === "user"
                        ? "bg-[var(--accent,#B4FF00)] text-[#060608]"
                        : "bg-white/[0.06] text-[#F0EFE8]"
                    }`}
                  >
                    {m.content ||
                      (running && m.role === "assistant" ? (
                        <span className="inline-flex gap-1 text-white/40">
                          <span className="animate-pulse">ÔùÅ</span>
                          <span className="animate-pulse [animation-delay:150ms]">
                            ÔùÅ
                          </span>
                          <span className="animate-pulse [animation-delay:300ms]">
                            ÔùÅ
                          </span>
                        </span>
                      ) : null)}
                  </div>
                </div>
              ))}
            </div>

            {/* TODO: Voice Mode ÔÇö ElevenLabs Integration (wenn Guthaben verf├╝gbar)
                Voice-ID: tbd, STT: browser SpeechRecognition API */}
            <form
              className="shrink-0 border-t border-white/[0.08] p-3"
              onSubmit={(e) => {
                e.preventDefault();
                void sendMessage(input);
              }}
            >
              <div className="flex items-center gap-2 rounded-xl border border-white/10 bg-white/[0.04] px-3 py-2 focus-within:border-[var(--accent,#B4FF00)] transition-colors">
                <input
                  ref={inputRef}
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  placeholder="Frag mich alles..."
                  disabled={running}
                  className="min-w-0 flex-1 bg-transparent text-sm text-[#F0EFE8] placeholder:text-white/35 outline-none"
                />
                <button
                  type="submit"
                  disabled={running || !input.trim()}
                  className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-[var(--accent,#B4FF00)] text-[#060608] disabled:opacity-35 hover:brightness-105 transition-all"
                  aria-label="Senden"
                >
                  <ArrowUp size={16} strokeWidth={2.5} />
                </button>
              </div>
            </form>
          </div>
        )}

        {!open && (
          <button
            type="button"
            onClick={() => setOpen(true)}
            title="Melodia ÔÇö Deine Assistentin"
            className="pointer-events-auto rounded-full focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--accent,#B4FF00)]"
            aria-label="Melodia ÔÇö Deine Assistentin"
          >
            {orb("lg")}
          </button>
        )}
      </div>
    </>
  );
}
